#[derive(Debug, Deserialize)]
pub struct InvoiceInput {
    pub invoice_number: String,
    pub contact_id: i64,
    pub issue_date: String,
    pub due_date: String,
    pub notes: Option<String>,
    pub terms: Option<String>,
