pub mod beancount;
pub mod qif;

pub use beancount::export_beancount;
pub use qif::export_qif;

use crate::{AccountType, ValidatedTransaction};

/// Map account type to QIF account type header.
fn qif_type(account_type: AccountType) -> &'static str {
    match account_type {
        AccountType::Asset => "Bank",
        AccountType::Liability => "CCard",
        AccountType::Equity => "Oth A",
        AccountType::Income => "Oth A",
        AccountType::Expense => "Oth A",
    }
}

/// Export transactions to QIF format for a given account type.
/// QIF is a per-account format, so the caller specifies which account type to export.
pub fn export_qif(transactions: &[ValidatedTransaction], account_type: AccountType) -> String {
    let mut out = String::new();

    out.push_str(&format!("!Type:{}\n", qif_type(account_type)));

    for tx in transactions {
        // Date in MM/DD/YYYY format (QIF standard)
        out.push_str(&format!(
            "D{}/{}/{}\n",
            tx.date.format("%m"),
            tx.date.format("%d"),
            tx.date.format("%Y")
        ));

        // Total amount (from the perspective of this account type)
        let amount = tx.balanced_total.to_cents() as f64 / 100.0;
        out.push_str(&format!("T{amount:.2}\n"));

        // Payee / description
        out.push_str(&format!("P{}\n", tx.description));

        // Memo
        if let Some(memo) = &tx.memo {
            out.push_str(&format!("M{memo}\n"));
        }

        // End of record
        out.push_str("^\n");
    }

    out
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::{AccountId, Money, TransactionLine, UnvalidatedTransaction};
    use chrono::NaiveDate;

    #[test]
    fn export_empty() {
        let out = export_qif(&[], AccountType::Asset);
        assert_eq!(out, "!Type:Bank\n");
    }

    #[test]
    fn export_single_transaction() {
        let tx = UnvalidatedTransaction {
            date: NaiveDate::from_ymd_opt(2026, 3, 15).unwrap(),
            description: "Coffee Shop".to_string(),
            lines: vec![
                TransactionLine::debit(AccountId(1), Money::from_cents(500), None),
                TransactionLine::credit(AccountId(2), Money::from_cents(500), None),
            ],
            memo: Some("Morning coffee".to_string()),
        };
        let validated = ValidatedTransaction::validate(tx).unwrap();
        let out = export_qif(&[validated], AccountType::Asset);

        assert!(out.contains("!Type:Bank"));
        assert!(out.contains("D03/15/2026"));
        assert!(out.contains("T5.00"));
        assert!(out.contains("PCoffee Shop"));
        assert!(out.contains("MMorning coffee"));
        assert!(out.contains("^"));
    }

    #[test]
    fn qif_type_mapping() {
        assert_eq!(qif_type(AccountType::Asset), "Bank");
        assert_eq!(qif_type(AccountType::Liability), "CCard");
    }
}

use chrono::Datelike;

use crate::Money;

use super::payment::Payment;

/// The IRS 1099-NEC reporting threshold: $600.
const NEC_THRESHOLD_CENTS: i64 = 60000;

/// Sum all payments within a calendar year.
pub fn compute_ytd_payments(payments: &[Payment], year: u16) -> Money {
    payments
        .iter()
        .filter(|p| p.date.year_ce().1 as u16 == year)
        .map(|p| p.amount)
        .fold(Money::zero(), |a, b| a + b)
}

/// Returns true if the YTD amount meets or exceeds the $600 1099-NEC threshold.
pub fn check_1099_threshold(ytd_amount: Money) -> bool {
    ytd_amount.to_cents() >= NEC_THRESHOLD_CENTS
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::invoice::InvoiceId;
    use chrono::NaiveDate;

    fn payment(cents: i64, year: i32, month: u32, day: u32) -> Payment {
        Payment {
            id: None,
            invoice_id: InvoiceId(1),
            amount: Money::from_cents(cents),
            date: NaiveDate::from_ymd_opt(year, month, day).unwrap(),
            method: None,
            transaction_id: None,
        }
    }

    #[test]
    fn ytd_payments_filters_by_year() {
        let payments = vec![
            payment(10000, 2025, 6, 1),
            payment(20000, 2026, 1, 15),
            payment(30000, 2026, 3, 10),
            payment(5000, 2027, 1, 1),
        ];
        let ytd = compute_ytd_payments(&payments, 2026);
        assert_eq!(ytd.to_cents(), 50000); // $200 + $300
    }

    #[test]
    fn ytd_payments_empty() {
        let ytd = compute_ytd_payments(&[], 2026);
        assert_eq!(ytd.to_cents(), 0);
    }

    #[test]
    fn threshold_at_600() {
        assert!(check_1099_threshold(Money::from_cents(60000)));
    }

    #[test]
    fn threshold_below_600() {
        assert!(!check_1099_threshold(Money::from_cents(59999)));
    }

    #[test]
    fn threshold_above_600() {
        assert!(check_1099_threshold(Money::from_cents(100000)));
    }

    #[test]
    fn threshold_zero() {
        assert!(!check_1099_threshold(Money::zero()));
    }
}

