#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct Money(Decimal);

impl Money {
    pub fn from_cents(cents: i64) -> Self {
        Money(Decimal::from(cents) / Decimal::from(100))
    }

    pub fn to_cents(self) -> i64 {
        (self.0 * Decimal::from(100)).to_i64().unwrap()
    }

    pub fn from_decimal(decimal: Decimal) -> Self {
        Money(decimal.round_dp(2))
    }

    pub fn zero() -> Self {
        Money(Decimal::ZERO)
    }

    pub fn is_zero(self) -> bool {
        self.0.is_zero()
    }

    /// Raw decimal value (for tax calculations that need intermediate precision).
    pub fn as_decimal(self) -> Decimal {
        self.0
    }

    /// Round to the nearest whole dollar (IRS rounding: half-up).
    pub fn round_to_dollar(self) -> Self {
        Money(
            self.0
                .round_dp_with_strategy(0, rust_decimal::RoundingStrategy::MidpointAwayFromZero),
        )
    }
}

impl fmt::Display for Money {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "${:.2}", self.0)
    }
}

impl Add for Money {
    type Output = Self;
    fn add(self, rhs: Self) -> Self {
        Money(self.0 + rhs.0)
    }
}

impl Sub for Money {
    type Output = Self;
    fn sub(self, rhs: Self) -> Self {
        Money(self.0 - rhs.0)
    }
}

impl Mul<Decimal> for Money {
    type Output = Self;
    fn mul(self, rhs: Decimal) -> Self {
        Money::from_decimal(self.0 * rhs)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn from_cents_roundtrip() {
        assert_eq!(Money::from_cents(100).to_cents(), 100);
        assert_eq!(Money::from_cents(-5000).to_cents(), -5000);
        assert_eq!(Money::from_cents(0).to_cents(), 0);
        assert_eq!(Money::from_cents(1).to_cents(), 1);
        assert_eq!(Money::from_cents(i64::MAX / 100).to_cents(), i64::MAX / 100);
    }

    #[test]
    fn display_formats_correctly() {
        assert_eq!(Money::from_cents(1000).to_string(), "$10.00");
        assert_eq!(Money::from_cents(1).to_string(), "$0.01");
        assert_eq!(Money::from_cents(0).to_string(), "$0.00");
        assert_eq!(Money::from_cents(-500).to_string(), "$-5.00");
        assert_eq!(Money::from_cents(100000).to_string(), "$1000.00");
    }

    #[test]
    fn add() {
        assert_eq!(
            (Money::from_cents(1000) + Money::from_cents(250)).to_cents(),
            1250
        );
        assert_eq!((Money::from_cents(0) + Money::from_cents(0)).to_cents(), 0);
        assert_eq!(
            (Money::from_cents(-500) + Money::from_cents(1000)).to_cents(),
            500
        );
    }

    #[test]
    fn sub() {
        assert_eq!(
            (Money::from_cents(1000) - Money::from_cents(250)).to_cents(),
            750
        );
        assert_eq!(
            (Money::from_cents(500) - Money::from_cents(500)).to_cents(),
            0
        );
        assert_eq!(
            (Money::from_cents(100) - Money::from_cents(200)).to_cents(),
            -100
        );
    }

    #[test]
    fn zero_and_is_zero() {
        assert!(Money::zero().is_zero());
        assert!(!Money::from_cents(1).is_zero());
        assert!(!Money::from_cents(-1).is_zero());
        assert_eq!(Money::zero().to_cents(), 0);
    }

    #[test]
    fn from_decimal_rounds_to_two_dp() {
        use rust_decimal::Decimal;
        use std::str::FromStr;
        let m = Money::from_decimal(Decimal::from_str("10.125").unwrap());
        // rust_decimal default rounding is MidpointNearestEven (banker's rounding)
        assert_eq!(m.to_cents(), 1012);
        let m = Money::from_decimal(Decimal::from_str("10.135").unwrap());
        assert_eq!(m.to_cents(), 1014);
    }

    #[test]
    fn ordering() {
        assert!(Money::from_cents(100) > Money::from_cents(50));
        assert!(Money::from_cents(-10) < Money::from_cents(0));
        assert_eq!(Money::from_cents(100), Money::from_cents(100));
    }

    #[test]
    fn mul_by_decimal() {
        use std::str::FromStr;
        let rate = Decimal::from_str("0.153").unwrap();
        // $1000.00 * 0.153 = $153.00
        assert_eq!((Money::from_cents(100_000) * rate).to_cents(), 15300);
    }

    #[test]
    fn round_to_dollar() {
        // $10.49 → $10.00
        assert_eq!(Money::from_cents(1049).round_to_dollar().to_cents(), 1000);
        // $10.50 → $11.00 (IRS half-up)
        assert_eq!(Money::from_cents(1050).round_to_dollar().to_cents(), 1100);
        // $10.99 → $11.00
        assert_eq!(Money::from_cents(1099).round_to_dollar().to_cents(), 1100);
    }

    #[test]
    fn as_decimal_roundtrip() {
        let m = Money::from_cents(1234);
        assert_eq!(Money::from_decimal(m.as_decimal()), m);
    }
}

use chrono::NaiveDate;
use serde::{Deserialize, Serialize};
use std::fmt;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub struct FiscalYear(pub u16);

impl fmt::Display for FiscalYear {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "FY{}", self.0)
    }
}

impl FiscalYear {
    pub fn new(year: u16) -> Self {
        FiscalYear(year)
    }

    pub fn year(self) -> u16 {
        self.0
    }

    pub fn start_date(self) -> NaiveDate {
        NaiveDate::from_ymd_opt(self.0 as i32, 1, 1).unwrap()
    }

    /// Returns December 31 of this fiscal year (inclusive end, matching Quarter::end_date).
    pub fn end_date(self) -> NaiveDate {
        NaiveDate::from_ymd_opt(self.0 as i32, 12, 31).unwrap()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub enum Quarter {
    Q1,
    Q2,
    Q3,
    Q4,
}

impl fmt::Display for Quarter {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Quarter::Q1 => write!(f, "Q1"),
            Quarter::Q2 => write!(f, "Q2"),
            Quarter::Q3 => write!(f, "Q3"),
            Quarter::Q4 => write!(f, "Q4"),
        }
    }
}

impl Quarter {
    pub fn new(n: u8) -> Option<Self> {
        match n {
            1 => Some(Quarter::Q1),
            2 => Some(Quarter::Q2),
            3 => Some(Quarter::Q3),
            4 => Some(Quarter::Q4),
            _ => None,
        }
    }

    pub fn start_date(self, year: FiscalYear) -> NaiveDate {
        match self {
            Quarter::Q1 => NaiveDate::from_ymd_opt(year.year() as i32, 1, 1).unwrap(),
            Quarter::Q2 => NaiveDate::from_ymd_opt(year.year() as i32, 4, 1).unwrap(),
            Quarter::Q3 => NaiveDate::from_ymd_opt(year.year() as i32, 7, 1).unwrap(),
            Quarter::Q4 => NaiveDate::from_ymd_opt(year.year() as i32, 10, 1).unwrap(),
        }
    }

    pub fn end_date(self, year: FiscalYear) -> NaiveDate {
        match self {
            Quarter::Q1 => NaiveDate::from_ymd_opt(year.year() as i32, 3, 31).unwrap(),
            Quarter::Q2 => NaiveDate::from_ymd_opt(year.year() as i32, 6, 30).unwrap(),
            Quarter::Q3 => NaiveDate::from_ymd_opt(year.year() as i32, 9, 30).unwrap(),
            Quarter::Q4 => NaiveDate::from_ymd_opt(year.year() as i32, 12, 31).unwrap(),
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
pub struct DateRange {
    pub start: NaiveDate,
    pub end: NaiveDate,
}

impl fmt::Display for DateRange {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{} to {}", self.start, self.end)
    }
}

impl DateRange {
    pub fn new(start: NaiveDate, end: NaiveDate) -> Self {
        DateRange { start, end }
    }

    pub fn contains(self, date: NaiveDate) -> bool {
        date >= self.start && date <= self.end
    }
}

