            description: "Empty".to_string(),
            lines: vec![],
            memo: None,
        };
        assert!(matches!(
            ValidatedTransaction::validate(tx),
            Err(LedgerError::EmptyTransaction)
        ));
    }

    #[test]
    fn validate_multi_line_balanced() {
        // Split transaction: one credit, two debits
        let tx = UnvalidatedTransaction {
            date: date(2024, 1, 15),
            description: "Split".to_string(),
            lines: vec![
                TransactionLine::debit(id(1), Money::from_cents(300), None),
                TransactionLine::debit(id(2), Money::from_cents(200), None),
                TransactionLine::credit(id(3), Money::from_cents(500), None),
            ],
            memo: None,
        };
        let validated = ValidatedTransaction::validate(tx).unwrap();
        assert_eq!(validated.balanced_total.to_cents(), 500);
    }

    #[test]
    fn total_debits_and_credits() {
        let tx = simple_tx(id(1), id(2), 1234);
        assert_eq!(tx.total_debits().to_cents(), 1234);
        assert_eq!(tx.total_credits().to_cents(), 1234);
    }

    #[test]
    fn transaction_line_constructors() {
        let d = TransactionLine::debit(id(5), Money::from_cents(100), Some("note".to_string()));
        assert_eq!(d.debit.to_cents(), 100);
        assert_eq!(d.credit.to_cents(), 0);
        assert_eq!(d.memo.as_deref(), Some("note"));

        let c = TransactionLine::credit(id(5), Money::from_cents(100), None);
        assert_eq!(c.debit.to_cents(), 0);
        assert_eq!(c.credit.to_cents(), 100);
    }
}

use serde::{Deserialize, Serialize};
use std::fmt;

/// SMTP connection settings for lettre.
#[derive(Clone, Serialize, Deserialize)]
pub struct SmtpConfig {
    pub host: String,
    pub port: u16,
    pub username: String,
    pub password: String,
    /// Use STARTTLS (port 587) vs implicit TLS (port 465).
    #[serde(default = "default_true")]
    pub starttls: bool,
}

fn default_true() -> bool {
    true
}

// Redact password in Debug output
impl fmt::Debug for SmtpConfig {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("SmtpConfig")
            .field("host", &self.host)
            .field("port", &self.port)
            .field("username", &self.username)
            .field("password", &"[REDACTED]")
            .field("starttls", &self.starttls)
            .finish()
    }
}

/// Email delivery configuration — either SMTP or Resend API.
#[derive(Clone, Deserialize)]
#[serde(tag = "backend")]
pub enum EmailConfig {
    /// Send via SMTP (lettre).
    #[serde(rename = "smtp")]
    Smtp {
        from_name: String,
        from_email: String,
        smtp: SmtpConfig,
    },
    /// Send via Resend HTTP API.
    #[serde(rename = "resend")]
    Resend {
        from_name: String,
        from_email: String,
        api_key: String,
    },
}

// Redact secrets in Debug output
impl fmt::Debug for EmailConfig {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            EmailConfig::Smtp {
                from_name,
                from_email,
                smtp,
            } => f
                .debug_struct("EmailConfig::Smtp")
                .field("from_name", from_name)
                .field("from_email", from_email)
                .field("smtp", smtp)
                .finish(),
            EmailConfig::Resend {
                from_name,
                from_email,
                ..
            } => f
                .debug_struct("EmailConfig::Resend")
                .field("from_name", from_name)
                .field("from_email", from_email)
                .field("api_key", &"[REDACTED]")
                .finish(),
        }
    }
}

impl EmailConfig {
    pub fn from_address(&self) -> (&str, &str) {
        match self {
            EmailConfig::Smtp {
                from_name,
                from_email,
                ..
            } => (from_name, from_email),
            EmailConfig::Resend {
                from_name,
                from_email,
                ..
            } => (from_name, from_email),
        }
    }
}

