        let e4 = DeliveryError::Smtp("timeout".into());
        assert_eq!(e4.to_string(), "SMTP delivery failed: timeout");

        let e5 = DeliveryError::Resend("429 rate limited".into());
        assert_eq!(e5.to_string(), "Resend API error: 429 rate limited");
    }

