            tx(2, (2024, 1, 15), "STARBUCKS", 500),
            tx(3, (2024, 1, 20), "WHOLE FOODS", 3000),
        ];
        let dups = find_duplicates(&txs, 3, 0.9);
        assert_eq!(dups.len(), 1);
        assert_eq!(dups[0], (1, 2));
