    fn find_duplicates_ignores_different_amounts() {
        let txs = vec![
            tx(1, (2024, 1, 15), "STARBUCKS", 500),
            tx(2, (2024, 1, 15), "STARBUCKS", 600),
        ];
        assert!(find_duplicates(&txs, 3, 0.9).is_empty());
    }

    #[test]
