use chrono::NaiveDate;
use rust_decimal::prelude::ToPrimitive;
use rust_decimal::Decimal;
use std::str::FromStr;
use thiserror::Error;

#[derive(Debug, Clone)]
pub struct OfxTransaction {
    pub fit_id: String,
    pub date: NaiveDate,
    pub amount: i64,
    pub memo: Option<String>,
    pub name: Option<String>,
    pub check_number: Option<String>,
}

#[derive(Debug, Clone)]
pub struct OfxAccount {
    pub account_id: String,
    pub bank_id: Option<String>,
    pub account_type: Option<String>,
}

#[derive(Debug, Clone)]
pub struct OfxStatement {
    pub account: OfxAccount,
    pub start_date: NaiveDate,
    pub end_date: NaiveDate,
    pub transactions: Vec<OfxTransaction>,
    pub currency: Option<String>,
}

#[derive(Error, Debug)]
pub enum OfxError {
    #[error("Failed to parse OFX: {0}")]
    ParseError(String),
    #[error("Missing required field: {0}")]
    MissingField(String),
    #[error("Invalid date format: {0}")]
    InvalidDate(String),
}

pub struct OfxParser;

impl OfxParser {
    pub fn parse(data: &str) -> Result<OfxStatement, OfxError> {
        let data = data.trim();

        let mut account = OfxAccount {
            account_id: String::new(),
            bank_id: None,
            account_type: None,
        };

        let mut start_date = None;
        let mut end_date = None;
        let mut transactions = Vec::new();
        let mut currency = None;

        let mut in_stmttrn = false;
        let mut current_trx: Option<BuildingTrx> = None;

        for line in data.lines() {
            let line = line.trim();
            if line.is_empty() {
                continue;
            }

            if let Some(tag) = line.strip_prefix('<') {
                let (tag_name, value) = if let Some((name, val)) = tag.split_once('>') {
                    (name.trim(), Some(val.trim().to_string()))
                } else {
                    (tag.trim_end_matches(&['>', '\r', '\n'][..]), None)
                };

                match tag_name.to_uppercase().as_str() {
                    "ACCTID" => {
                        if let Some(v) = value {
                            account.account_id = v;
                        }
                    }
                    "BANKID" => {
                        if let Some(v) = value {
                            account.bank_id = Some(v);
                        }
                    }
                    "ACCTTYPE" => {
                        if let Some(v) = value {
                            account.account_type = Some(v);
                        }
                    }
                    "DTSTART" => {
                        if let Some(v) = value {
                            start_date = parse_ofx_date(&v);
                        }
                    }
                    "DTEND" => {
                        if let Some(v) = value {
                            end_date = parse_ofx_date(&v);
                        }
                    }
                    "CURDEF" => {
                        if let Some(v) = value {
                            currency = Some(v);
                        }
                    }
                    "STMTTRN" => {
                        in_stmttrn = true;
                        current_trx = Some(BuildingTrx::default());
                    }
                    "/STMTTRN" => {
                        if let Some(trx) = current_trx.take() {
                            if let Some(date) = trx.date {
                                transactions.push(OfxTransaction {
                                    fit_id: trx.fit_id.unwrap_or_default(),
                                    date,
                                    amount: trx.amount.unwrap_or(0),
                                    memo: trx.memo,
                                    name: trx.name,
                                    check_number: trx.check_number,
                                });
                            }
                        }
                        in_stmttrn = false;
                    }
                    _ => {
                        if in_stmttrn {
                            if let Some(ref mut trx) = current_trx {
                                match tag_name.to_uppercase().as_str() {
                                    "FITID" => {
                                        if let Some(v) = value {
                                            trx.fit_id = Some(v);
                                        }
                                    }
                                    "DTPOSTED" => {
                                        if let Some(v) = value {
                                            trx.date = parse_ofx_date(&v);
                                        }
                                    }
                                    "TRNAMT" => {
                                        if let Some(v) = value {
                                            trx.amount = parse_ofx_amount(&v);
                                        }
                                    }
                                    "MEMO" => {
                                        if let Some(v) = value {
                                            trx.memo = Some(v);
                                        }
                                    }
                                    "NAME" => {
                                        if let Some(v) = value {
                                            trx.name = Some(v);
                                        }
                                    }
                                    "CHECKNUM" => {
                                        if let Some(v) = value {
                                            trx.check_number = Some(v);
                                        }
                                    }
                                    _ => {}
                                }
                            }
                        }
                    }
                }
            }
        }

        let start_date = start_date.ok_or(OfxError::MissingField("DTSTART".to_string()))?;
        let end_date = end_date.ok_or(OfxError::MissingField("DTEND".to_string()))?;

        if account.account_id.is_empty() {
            return Err(OfxError::MissingField("ACCTID".to_string()));
        }

        Ok(OfxStatement {
            account,
            start_date,
            end_date,
            transactions,
            currency,
        })
    }
}

#[derive(Default)]
struct BuildingTrx {
    fit_id: Option<String>,
    date: Option<NaiveDate>,
    amount: Option<i64>,
    memo: Option<String>,
    name: Option<String>,
    check_number: Option<String>,
}

fn parse_ofx_date(s: &str) -> Option<NaiveDate> {
    let s = s.trim();
    if s.len() >= 8 {
        let y: i32 = s[0..4].parse().ok()?;
        let m: u32 = s[4..6].parse().ok()?;
        let d: u32 = s[6..8].parse().ok()?;

        if let Some(date) = NaiveDate::from_ymd_opt(y, m, d) {
            return Some(date);
        }
    }

    if let Ok(dt) = chrono::DateTime::parse_from_rfc3339(s) {
        return Some(dt.date_naive());
    }

    None
}

fn parse_ofx_amount(s: &str) -> Option<i64> {
    let s = s.trim();
    let s = s.replace(',', "");
    let dec = Decimal::from_str(&s).ok()?;
    (dec * Decimal::from(100)).round().to_i64()
}

pub fn parse(data: &[u8]) -> Result<OfxStatement, OfxError> {
    // Guard against pathologically large input
    const MAX_OFX_SIZE: usize = 50 * 1024 * 1024; // 50MB
    if data.len() > MAX_OFX_SIZE {
        return Err(OfxError::ParseError(format!(
            "OFX file too large ({} bytes, max {})",
            data.len(),
            MAX_OFX_SIZE
        )));
    }

    let content = String::from_utf8_lossy(data);
    OfxParser::parse(&content)
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── unit helpers ──────────────────────────────────────────────────────────

    #[test]
    fn parse_ofx_date_8digit() {
        assert_eq!(
            parse_ofx_date("20240115"),
            Some(NaiveDate::from_ymd_opt(2024, 1, 15).unwrap())
        );
        assert_eq!(
            parse_ofx_date("20240301"),
            Some(NaiveDate::from_ymd_opt(2024, 3, 1).unwrap())
        );
    }

    #[test]
    fn parse_ofx_date_with_time_suffix_ignored() {
        // Banks sometimes emit e.g. "20240115120000[-5:EST]" — only first 8 chars used
        assert_eq!(
            parse_ofx_date("20240115120000[-5:EST]"),
            Some(NaiveDate::from_ymd_opt(2024, 1, 15).unwrap())
        );
    }

    #[test]
    fn parse_ofx_date_invalid_returns_none() {
        assert_eq!(parse_ofx_date("not-a-date"), None);
        assert_eq!(parse_ofx_date(""), None);
    }

    #[test]
    fn parse_ofx_amount_positive() {
        assert_eq!(parse_ofx_amount("123.45"), Some(12345));
        assert_eq!(parse_ofx_amount("0.99"), Some(99));
        assert_eq!(parse_ofx_amount("0.01"), Some(1));
    }

    #[test]
    fn parse_ofx_amount_negative() {
        assert_eq!(parse_ofx_amount("-50.00"), Some(-5000));
        assert_eq!(parse_ofx_amount("-0.01"), Some(-1));
    }

    #[test]
    fn parse_ofx_amount_with_commas() {
        assert_eq!(parse_ofx_amount("1,234.56"), Some(123456));
    }

    #[test]
    fn parse_ofx_amount_invalid_returns_none() {
        assert_eq!(parse_ofx_amount("abc"), None);
        assert_eq!(parse_ofx_amount(""), None);
    }

    // ── full statement parse ──────────────────────────────────────────────────

    const SAMPLE_OFX: &str = r#"
OFXHEADER:100
DATA:OFXSGML
VERSION:102

<OFX>
<BANKMSGSRSV1>
<STMTTRNRS>
<STMTRS>
<CURDEF>USD
<BANKACCTFROM>
<BANKID>123456789
<ACCTID>000112345
<ACCTTYPE>CHECKING
</BANKACCTFROM>
<BANKTRANLIST>
<DTSTART>20240101
<DTEND>20240131
<STMTTRN>
<TRNTYPE>DEBIT
<DTPOSTED>20240115
<TRNAMT>-49.99
<FITID>TXN001
<NAME>AMAZON MARKETPLACE
<MEMO>Online purchase
</STMTTRN>
<STMTTRN>
<TRNTYPE>CREDIT
<DTPOSTED>20240120
<TRNAMT>1500.00
<FITID>TXN002
<NAME>DIRECT DEPOSIT
</STMTTRN>
</BANKTRANLIST>
</STMTRS>
</STMTTRNRS>
</BANKMSGSRSV1>
</OFX>
"#;

    #[test]
    fn parse_full_ofx_statement() {
        let stmt = parse(SAMPLE_OFX.as_bytes()).unwrap();

        assert_eq!(stmt.account.account_id, "000112345");
        assert_eq!(stmt.account.bank_id.as_deref(), Some("123456789"));
        assert_eq!(stmt.account.account_type.as_deref(), Some("CHECKING"));
        assert_eq!(
            stmt.start_date,
            NaiveDate::from_ymd_opt(2024, 1, 1).unwrap()
        );
        assert_eq!(stmt.end_date, NaiveDate::from_ymd_opt(2024, 1, 31).unwrap());
        assert_eq!(stmt.currency.as_deref(), Some("USD"));
        assert_eq!(stmt.transactions.len(), 2);
    }

    #[test]
    fn parse_ofx_transaction_fields() {
        let stmt = parse(SAMPLE_OFX.as_bytes()).unwrap();
        let t0 = &stmt.transactions[0];
        assert_eq!(t0.fit_id, "TXN001");
        assert_eq!(t0.date, NaiveDate::from_ymd_opt(2024, 1, 15).unwrap());
        assert_eq!(t0.amount, -4999);
        assert_eq!(t0.name.as_deref(), Some("AMAZON MARKETPLACE"));
        assert_eq!(t0.memo.as_deref(), Some("Online purchase"));
    }

    #[test]
    fn parse_ofx_second_transaction() {
        let stmt = parse(SAMPLE_OFX.as_bytes()).unwrap();
        let t1 = &stmt.transactions[1];
        assert_eq!(t1.fit_id, "TXN002");
        assert_eq!(t1.amount, 150000);
        assert!(t1.memo.is_none());
    }

    #[test]
    fn parse_ofx_missing_account_id_errors() {
        let bad = r#"
<OFX>
<BANKMSGSRSV1><STMTTRNRS><STMTRS>
<CURDEF>USD
<BANKACCTFROM></BANKACCTFROM>
<BANKTRANLIST>
<DTSTART>20240101
<DTEND>20240131
</BANKTRANLIST>
</STMTRS></STMTTRNRS></BANKMSGSRSV1>
</OFX>
"#;
        assert!(parse(bad.as_bytes()).is_err());
    }

    #[test]
    fn parse_ofx_missing_dates_errors() {
        let bad = r#"
<OFX>
<BANKMSGSRSV1><STMTTRNRS><STMTRS>
<BANKACCTFROM>
<ACCTID>12345
</BANKACCTFROM>
<BANKTRANLIST>
</BANKTRANLIST>
</STMTRS></STMTTRNRS></BANKMSGSRSV1>
</OFX>
"#;
        assert!(parse(bad.as_bytes()).is_err());
    }
}

use serde::{Deserialize, Serialize};
use thiserror::Error;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum PlaidEnvironment {
    Sandbox,
    Development,
    Production,
}

impl PlaidEnvironment {
    pub fn base_url(&self) -> &str {
        match self {
            PlaidEnvironment::Sandbox => "https://sandbox.plaid.com",
            PlaidEnvironment::Development => "https://development.plaid.com",
            PlaidEnvironment::Production => "https://production.plaid.com",
        }
    }
}

#[derive(Clone, Deserialize)]
pub struct PlaidConfig {
    pub client_id: String,
    pub secret: String,
    pub environment: PlaidEnvironment,
}

// Redact secret in Debug output
impl std::fmt::Debug for PlaidConfig {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PlaidConfig")
            .field("client_id", &self.client_id)
            .field("secret", &"[REDACTED]")
            .field("environment", &self.environment)
            .finish()
    }
}

// ---------------------------------------------------------------------------
// Error
// ---------------------------------------------------------------------------

#[derive(Debug, Error)]
pub enum PlaidError {
    #[error("HTTP error: {0}")]
    Http(#[from] reqwest::Error),

    #[error("Plaid API error: {error_type} — {error_message}")]
    Api {
        error_type: String,
        error_code: String,
        error_message: String,
    },

    #[error("Deserialization error: {0}")]
    Deserialize(String),
}

// ---------------------------------------------------------------------------
// API request/response types
// ---------------------------------------------------------------------------

#[derive(Debug, Serialize)]
struct LinkTokenCreateRequest {
    client_id: String,
    secret: String,
    user: LinkTokenUser,
    client_name: String,
    products: Vec<String>,
    country_codes: Vec<String>,
    language: String,
}

#[derive(Debug, Serialize)]
struct LinkTokenUser {
    client_user_id: String,
}

#[derive(Debug, Deserialize, Serialize)]
pub struct LinkTokenResponse {
    pub link_token: String,
    pub expiration: String,
    pub request_id: String,
}

#[derive(Debug, Serialize)]
struct ExchangeTokenRequest {
    client_id: String,
    secret: String,
    public_token: String,
}

#[derive(Debug, Deserialize, Serialize)]
pub struct ExchangeTokenResponse {
    pub access_token: String,
    pub item_id: String,
    pub request_id: String,
}

#[derive(Debug, Serialize)]
struct TransactionsGetRequest {
    client_id: String,
    secret: String,
    access_token: String,
    start_date: String,
    end_date: String,
    options: TransactionsGetOptions,
}

#[derive(Debug, Serialize)]
struct TransactionsGetOptions {
    count: u32,
    offset: u32,
}

#[derive(Debug, Deserialize, Serialize)]
pub struct TransactionsGetResponse {
    pub accounts: Vec<PlaidAccount>,
    pub transactions: Vec<PlaidTransaction>,
    pub total_transactions: u32,
    pub request_id: String,
}

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct PlaidTransaction {
    pub transaction_id: String,
    pub name: String,
    pub amount: f64,
    pub date: String,
    pub category: Option<Vec<String>>,
    pub account_id: String,
    pub pending: bool,
    pub iso_currency_code: Option<String>,
    pub merchant_name: Option<String>,
}

impl PlaidTransaction {
    /// Convert the Plaid amount (f64 dollars) to cents (i64).
    /// Plaid amounts are positive for debits and negative for credits
    /// (from the user's perspective).
    pub fn amount_cents(&self) -> i64 {
        // Use string conversion to avoid f64 precision loss for large amounts
        let s = format!("{:.2}", self.amount);
        if let Some((whole, frac)) = s.split_once('.') {
            let sign = if self.amount < 0.0 { -1i64 } else { 1i64 };
            let whole_abs: i64 = whole.trim_start_matches('-').parse().unwrap_or(0);
            let frac_val: i64 = frac.parse().unwrap_or(0);
            sign * (whole_abs * 100 + frac_val)
        } else {
            (self.amount * 100.0).round() as i64
        }
    }
}

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct PlaidAccount {
    pub account_id: String,
    pub name: String,
    #[serde(rename = "type")]
    pub account_type: String,
    pub subtype: Option<String>,
    pub balances: PlaidBalances,
}

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct PlaidBalances {
    pub available: Option<f64>,
    pub current: Option<f64>,
    pub limit: Option<f64>,
    pub iso_currency_code: Option<String>,
}

/// Plaid API error response body.
#[derive(Debug, Deserialize)]
struct PlaidApiErrorBody {
    error_type: String,
    error_code: String,
    error_message: String,
}

// ---------------------------------------------------------------------------
// Client
// ---------------------------------------------------------------------------

pub struct PlaidClient {
    http: reqwest::Client,
    config: PlaidConfig,
}

impl PlaidClient {
    pub fn new(config: PlaidConfig) -> Self {
        let http = reqwest::Client::builder()
            .timeout(std::time::Duration::from_secs(30))
            .build()
            .expect("failed to build HTTP client");
        Self { http, config }
    }

    fn base_url(&self) -> &str {
        self.config.environment.base_url()
    }

    /// Create a Link token for initializing Plaid Link in the frontend.
    pub async fn create_link_token(
        &self,
        user_id: &str,
    ) -> Result<LinkTokenResponse, PlaidError> {
        let body = LinkTokenCreateRequest {
            client_id: self.config.client_id.clone(),
            secret: self.config.secret.clone(),
            user: LinkTokenUser {
                client_user_id: user_id.to_string(),
            },
            client_name: "Aequi".to_string(),
            products: vec!["transactions".to_string()],
            country_codes: vec!["US".to_string()],
            language: "en".to_string(),
        };

        let resp = self
            .http
            .post(format!("{}/link/token/create", self.base_url()))
            .json(&body)
            .send()
            .await?;

        self.handle_response(resp).await
    }

    /// Exchange a public token (received from Plaid Link) for an access token.
    pub async fn exchange_public_token(
        &self,
        public_token: &str,
    ) -> Result<ExchangeTokenResponse, PlaidError> {
        let body = ExchangeTokenRequest {
            client_id: self.config.client_id.clone(),
            secret: self.config.secret.clone(),
            public_token: public_token.to_string(),
        };

        let resp = self
            .http
            .post(format!("{}/item/public_token/exchange", self.base_url()))
            .json(&body)
            .send()
            .await?;

        self.handle_response(resp).await
    }

    /// Fetch all transactions for the given date range (handles pagination).
    pub async fn get_transactions(
        &self,
        access_token: &str,
        start_date: &str,
        end_date: &str,
    ) -> Result<TransactionsGetResponse, PlaidError> {
        let mut all_transactions = Vec::new();
        let mut accounts = Vec::new();
        let mut offset = 0u32;
        let page_size = 500u32;
        let mut total;
        let mut request_id;

        loop {
            let body = TransactionsGetRequest {
                client_id: self.config.client_id.clone(),
                secret: self.config.secret.clone(),
                access_token: access_token.to_string(),
                start_date: start_date.to_string(),
                end_date: end_date.to_string(),
                options: TransactionsGetOptions {
                    count: page_size,
                    offset,
                },
            };

            let resp = self
                .http
                .post(format!("{}/transactions/get", self.base_url()))
                .json(&body)
                .send()
                .await?;

            let page: TransactionsGetResponse = self.handle_response(resp).await?;

            total = page.total_transactions;
            request_id = page.request_id;
            if accounts.is_empty() {
                accounts = page.accounts;
            }
            all_transactions.extend(page.transactions);

            offset += page_size;
            if offset >= total {
                break;
            }
        }

        Ok(TransactionsGetResponse {
            accounts,
            transactions: all_transactions,
            total_transactions: total,
            request_id,
        })
    }

    async fn handle_response<T: serde::de::DeserializeOwned>(
        &self,
        resp: reqwest::Response,
    ) -> Result<T, PlaidError> {
        let status = resp.status();
        let text = resp.text().await?;

        if !status.is_success() {
            if let Ok(err_body) = serde_json::from_str::<PlaidApiErrorBody>(&text) {
                return Err(PlaidError::Api {
                    error_type: err_body.error_type,
                    error_code: err_body.error_code,
                    error_message: err_body.error_message,
                });
            }
            let mut truncated = text;
            truncated.truncate(500);
            return Err(PlaidError::Deserialize(format!(
                "HTTP {status}: {truncated}"
            )));
        }

        serde_json::from_str(&text).map_err(|e| PlaidError::Deserialize(e.to_string()))
    }
}

