            "date": "2026-03-01",
            "category": null,
            "account_id": "acc_xyz",
            "pending": false,
            "iso_currency_code": "USD",
            "merchant_name": null
        }"#;
        let tx: PlaidTransaction = serde_json::from_str(json).unwrap();
        assert_eq!(tx.amount_cents(), -150050);
