use serde_json::json;

use aequi_core::{Money, TransactionLine, UnvalidatedTransaction, ValidatedTransaction};

use crate::protocol::{ToolDefinition, ToolResult};
use crate::tools::ToolRegistry;

pub fn register(registry: &mut ToolRegistry) {
    registry.register(
        ToolDefinition {
            name: "aequi_get_transactions".to_string(),
            description: "List recent transactions, optionally filtered by date range".to_string(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "start_date": { "type": "string", "description": "YYYY-MM-DD" },
                    "end_date": { "type": "string", "description": "YYYY-MM-DD" },
                    "limit": { "type": "integer", "default": 50 }
                }
            }),
        },
        false,
        |db, params| async move {
            let limit = params.get("limit").and_then(|v| v.as_i64()).unwrap_or(50);
            let rows = sqlx::query_as::<_, (i64, String, String, Option<String>, i64)>(
                "SELECT id, date, description, memo, balanced_total_cents FROM transactions ORDER BY date DESC LIMIT ?"
            )
            .bind(limit)
            .fetch_all(&db)
            .await;

            match rows {
                Ok(rows) => {
                    let txs: Vec<_> = rows.iter().map(|r| json!({
                        "id": r.0, "date": r.1, "description": r.2,
                        "memo": r.3, "balanced_total_cents": r.4
                    })).collect();
                    ToolResult::text(serde_json::to_string_pretty(&txs).unwrap())
                }
                Err(e) => ToolResult::error(e.to_string()),
            }
        },
    );

    registry.register(
        ToolDefinition {
            name: "aequi_create_transaction".to_string(),
            description: "Create a double-entry transaction".to_string(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "date": { "type": "string", "description": "YYYY-MM-DD" },
                    "description": { "type": "string" },
                    "lines": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "properties": {
                                "account_code": { "type": "string" },
                                "debit_cents": { "type": "integer" },
                                "credit_cents": { "type": "integer" }
                            },
                            "required": ["account_code", "debit_cents", "credit_cents"]
                        }
                    }
                },
                "required": ["date", "description", "lines"]
            }),
        },
        true,
        |db, params| async move {
            let date_str = params.get("date").and_then(|v| v.as_str()).unwrap_or("");
            let date = match chrono::NaiveDate::parse_from_str(date_str, "%Y-%m-%d") {
                Ok(d) => d,
                Err(e) => return ToolResult::error(format!("Invalid date: {e}")),
            };

            let description = params.get("description").and_then(|v| v.as_str()).unwrap_or("").to_string();
            let lines_val = match params.get("lines").and_then(|v| v.as_array()) {
                Some(l) => l,
                None => return ToolResult::error("lines is required".to_string()),
            };

            let mut lines = Vec::new();
            for line in lines_val {
                let code = line.get("account_code").and_then(|v| v.as_str()).unwrap_or("");
                let account = match aequi_storage::get_account_by_code(&db, code).await {
                    Ok(Some(a)) => a,
                    Ok(None) => return ToolResult::error(format!("Account {code} not found")),
                    Err(e) => return ToolResult::error(e.to_string()),
                };
                let debit = line.get("debit_cents").and_then(|v| v.as_i64()).unwrap_or(0);
                let credit = line.get("credit_cents").and_then(|v| v.as_i64()).unwrap_or(0);
                lines.push(TransactionLine {
                    account_id: account.id.unwrap(),
                    debit: Money::from_cents(debit),
                    credit: Money::from_cents(credit),
                    memo: None,
                });
            }

            let tx = UnvalidatedTransaction { date, description, lines, memo: None };
            let validated = match ValidatedTransaction::validate(tx) {
                Ok(v) => v,
                Err(e) => return ToolResult::error(e.to_string()),
            };

            let row = sqlx::query_as::<_, (i64,)>(
                "INSERT INTO transactions (date, description, memo, balanced_total_cents) VALUES (?, ?, ?, ?) RETURNING id"
            )
            .bind(validated.date.to_string())
            .bind(&validated.description)
            .bind(&validated.memo)
            .bind(validated.balanced_total.to_cents())
            .fetch_one(&db)
            .await;

            let id = match row {
                Ok(r) => r.0,
                Err(e) => return ToolResult::error(e.to_string()),
            };

            for line in &validated.lines {
                let _ = sqlx::query(
                    "INSERT INTO transaction_lines (transaction_id, account_id, debit_cents, credit_cents, memo) VALUES (?, ?, ?, ?, ?)"
                )
                .bind(id)
                .bind(line.account_id.0)
                .bind(line.debit.to_cents())
                .bind(line.credit.to_cents())
                .bind(&line.memo)
                .execute(&db)
                .await;
            }

            ToolResult::text(json!({ "id": id, "status": "created" }).to_string())
        },
    );

    registry.register(
        ToolDefinition {
            name: "aequi_get_profit_loss".to_string(),
            description: "Get profit & loss summary for a date range".to_string(),
            input_schema: json!({
                "type": "object",
                "properties": {
                    "start_date": { "type": "string", "description": "YYYY-MM-DD (default: Jan 1 current year)" },
                    "end_date": { "type": "string", "description": "YYYY-MM-DD (default: today)" }
                }
            }),
        },
        false,
        |db, params| async move {
            let today = chrono::Utc::now().date_naive();
            let default_start = format!("{}-01-01", today.format("%Y"));
            let start = params.get("start_date").and_then(|v| v.as_str()).unwrap_or(&default_start);
            let today_str = today.to_string();
            let end = params.get("end_date").and_then(|v| v.as_str()).unwrap_or(&today_str);

            let income_rows = sqlx::query_as::<_, (String, String, i64)>(
                r#"SELECT a.code, a.name, COALESCE(SUM(tl.credit_cents - tl.debit_cents), 0) AS net
                   FROM accounts a
                   JOIN transaction_lines tl ON tl.account_id = a.id
                   JOIN transactions t ON t.id = tl.transaction_id
                   WHERE a.account_type = 'Income' AND t.date >= ? AND t.date <= ?
                   GROUP BY a.id ORDER BY a.code"#
            )
            .bind(start).bind(end)
            .fetch_all(&db).await;

            let expense_rows = sqlx::query_as::<_, (String, String, i64)>(
                r#"SELECT a.code, a.name, COALESCE(SUM(tl.debit_cents - tl.credit_cents), 0) AS net
                   FROM accounts a
                   JOIN transaction_lines tl ON tl.account_id = a.id
                   JOIN transactions t ON t.id = tl.transaction_id
                   WHERE a.account_type = 'Expense' AND t.date >= ? AND t.date <= ?
                   GROUP BY a.id ORDER BY a.code"#
            )
            .bind(start).bind(end)
            .fetch_all(&db).await;

            let (income, expenses) = match (income_rows, expense_rows) {
                (Ok(i), Ok(e)) => (i, e),
                (Err(e), _) | (_, Err(e)) => return ToolResult::error(e.to_string()),
            };

            let total_income: i64 = income.iter().map(|r| r.2).sum();
            let total_expenses: i64 = expenses.iter().map(|r| r.2).sum();
            let net_profit = total_income - total_expenses;

            let income_lines: Vec<_> = income.iter().map(|r| json!({
                "code": r.0, "name": r.1, "amount_cents": r.2
            })).collect();
            let expense_lines: Vec<_> = expenses.iter().map(|r| json!({
                "code": r.0, "name": r.1, "amount_cents": r.2
            })).collect();

            ToolResult::text(serde_json::to_string_pretty(&json!({
                "period": { "start": start, "end": end },
                "income": income_lines,
                "expenses": expense_lines,
                "total_income_cents": total_income,
                "total_expenses_cents": total_expenses,
                "net_profit_cents": net_profit
            })).unwrap())
        },
    );
}

use std::sync::OnceLock;

use chrono::NaiveDate;
use regex::Regex;
use rust_decimal::prelude::ToPrimitive;
use rust_decimal::Decimal;
use std::str::FromStr;

use crate::types::{ExtractedField, ExtractedReceipt, PaymentMethod};

// ── Compiled regex cache ─────────────────────────────────────────────────────

macro_rules! re {
    ($name:ident, $pat:expr) => {
        fn $name() -> &'static Regex {
            static R: OnceLock<Regex> = OnceLock::new();
            R.get_or_init(|| Regex::new($pat).expect("invalid regex"))
        }
    };
}

re!(
    re_amount_label,
    r"(?i)\b(?:total|grand\s+total|amount\s+due|balance\s+due|total\s+due)\s*[:\$]?\s*\$?\s*([\d,]+\.\d{2})\b"
);
re!(
    re_subtotal,
    r"(?i)\bsubtotal\b\s*[:\$]?\s*\$?\s*([\d,]+\.\d{2})\b"
);
re!(
    re_tax,
    r"(?i)\b(?:tax|hst|gst|pst|vat|sales\s*tax)\b\s*[:\$]?\s*\$?\s*([\d,]+\.\d{2})\b"
);
re!(re_currency, r"\$\s*([\d,]+\.\d{2})");

re!(
    re_date_month_name,
    r"(?i)\b(january|february|march|april|may|june|july|august|september|october|november|december)\s+(\d{1,2}),?\s+(\d{4})\b"
);
re!(
    re_date_abbr_month,
    r"(?i)\b(\d{1,2})\s+(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)\.?\s+(\d{4})\b"
);
re!(re_date_iso, r"\b(\d{4})-(\d{2})-(\d{2})\b");
re!(re_date_slash, r"\b(\d{1,2})/(\d{1,2})/(\d{2,4})\b");
re!(re_date_dash, r"\b(\d{1,2})-(\d{1,2})-(\d{2,4})\b");

re!(
    re_payment,
    r"(?i)\b(visa|mastercard|master\s*card|amex|american\s+express|discover|cash|debit|check|cheque)\b"
);

re!(re_phone, r"\(?\d{3}\)?[\s\-]\d{3}[\s\-]\d{4}");
re!(re_url, r"(?i)(https?://|www\.)\S+");

// ── Public extraction API ─────────────────────────────────────────────────────

pub struct Extractor;

impl Extractor {
    /// Extract structured fields from raw OCR text.
    pub fn extract(ocr_text: &str) -> ExtractedReceipt {
        let vendor = Self::extract_vendor(ocr_text);
        let date = Self::extract_date(ocr_text);
        let total_cents = Self::extract_total(ocr_text);
        let subtotal_cents = Self::extract_subtotal(ocr_text);
        let tax_cents = Self::extract_tax(ocr_text);
        let payment_method = Self::extract_payment_method(ocr_text);

        // Aggregate confidence: weighted sum of key fields.
        let confidence = {
            let weighted = [
                (vendor.as_ref().map(|f| f.confidence), 0.25f32),
                (date.as_ref().map(|f| f.confidence), 0.30),
                (total_cents.as_ref().map(|f| f.confidence), 0.35),
                (payment_method.as_ref().map(|f| f.confidence), 0.10),
            ];
            let (score, weight) = weighted
                .iter()
                .fold((0.0f32, 0.0f32), |(s, w), (conf, fw)| {
                    (s + conf.unwrap_or(0.0) * fw, w + fw)
                });
            if weight > 0.0 {
                score / weight
            } else {
                0.0
            }
        };

        ExtractedReceipt {
            vendor,
            date,
            subtotal_cents,
            tax_cents,
            total_cents,
            payment_method,
            line_items: vec![],
            confidence,
        }
    }

    // ── Vendor ────────────────────────────────────────────────────────────────

    fn extract_vendor(text: &str) -> Option<ExtractedField<String>> {
        let candidate = text
            .lines()
            .take(10)
            .map(str::trim)
            .filter(|l| !l.is_empty())
            .filter(|l| !re_phone().is_match(l))
            .filter(|l| !re_url().is_match(l))
            .filter(|l| !re_date_slash().is_match(l) && !re_date_iso().is_match(l))
            .filter(|l| l.len() >= 3 && l.len() <= 50)
            // Skip lines that start with a digit (likely address or amount)
            .filter(|l| !l.starts_with(|c: char| c.is_ascii_digit()))
            .max_by_key(|l| {
                let all_caps = l
                    .chars()
                    .filter(|c| c.is_alphabetic())
                    .all(|c| c.is_uppercase());
                (if all_caps { 2i32 } else { 0 }) + (l.len() as i32).min(20)
            })?;

        Some(ExtractedField::new(candidate.to_string(), 0.60))
    }

    // ── Date ─────────────────────────────────────────────────────────────────

    fn extract_date(text: &str) -> Option<ExtractedField<NaiveDate>> {
        // Try patterns from most to least specific.
        if let Some(d) = try_date_month_name(text) {
            return Some(ExtractedField::new(d, 0.90));
        }
        if let Some(d) = try_date_abbr_month(text) {
            return Some(ExtractedField::new(d, 0.90));
        }
        if let Some(d) = try_date_iso(text) {
            return Some(ExtractedField::new(d, 0.95));
        }
        if let Some(d) = try_date_slash(text) {
            return Some(ExtractedField::new(d, 0.75));
        }
        if let Some(d) = try_date_dash(text) {
            return Some(ExtractedField::new(d, 0.70));
        }
        None
    }

    // ── Amounts ───────────────────────────────────────────────────────────────

    fn extract_total(text: &str) -> Option<ExtractedField<i64>> {
        // Prefer a labeled total over any raw dollar amount.
        if let Some(c) = re_amount_label().captures(text) {
            if let Some(cents) = parse_amount_str(c.get(1)?.as_str()) {
                return Some(ExtractedField::new(cents, 0.92));
            }
        }
        // Fall back to the largest dollar value on the page.
        re_currency()
            .captures_iter(text)
            .filter_map(|c| parse_amount_str(c.get(1)?.as_str()))
            .max()
            .map(|cents| ExtractedField::new(cents, 0.55))
    }

    fn extract_subtotal(text: &str) -> Option<ExtractedField<i64>> {
        let c = re_subtotal().captures(text)?;
        let cents = parse_amount_str(c.get(1)?.as_str())?;
        Some(ExtractedField::new(cents, 0.88))
    }

    fn extract_tax(text: &str) -> Option<ExtractedField<i64>> {
        let c = re_tax().captures(text)?;
        let cents = parse_amount_str(c.get(1)?.as_str())?;
        Some(ExtractedField::new(cents, 0.88))
    }

    // ── Payment method ────────────────────────────────────────────────────────

    fn extract_payment_method(text: &str) -> Option<ExtractedField<PaymentMethod>> {
        let c = re_payment().captures(text)?;
        let method = match c.get(1)?.as_str().to_lowercase().replace(' ', "").as_str() {
            "visa" => PaymentMethod::Visa,
            "mastercard" | "mc" => PaymentMethod::Mastercard,
            "amex" | "americanexpress" => PaymentMethod::Amex,
            "discover" => PaymentMethod::Discover,
            "cash" => PaymentMethod::Cash,
            "debit" => PaymentMethod::Debit,
            "check" | "cheque" => PaymentMethod::Check,
            other => PaymentMethod::Other(other.to_string()),
        };
        Some(ExtractedField::new(method, 0.90))
    }
}

// ── Date helpers ──────────────────────────────────────────────────────────────

fn try_date_month_name(text: &str) -> Option<NaiveDate> {
    let c = re_date_month_name().captures(text)?;
    let month = month_name_to_num(c.get(1)?.as_str())?;
    let day: u32 = c.get(2)?.as_str().parse().ok()?;
    let year: i32 = c.get(3)?.as_str().parse().ok()?;
    NaiveDate::from_ymd_opt(year, month, day)
}

fn try_date_abbr_month(text: &str) -> Option<NaiveDate> {
    let c = re_date_abbr_month().captures(text)?;
    let day: u32 = c.get(1)?.as_str().parse().ok()?;
    let month = abbr_month_to_num(c.get(2)?.as_str())?;
    let year: i32 = c.get(3)?.as_str().parse().ok()?;
    NaiveDate::from_ymd_opt(year, month, day)
}

fn try_date_iso(text: &str) -> Option<NaiveDate> {
    let c = re_date_iso().captures(text)?;
    let y: i32 = c.get(1)?.as_str().parse().ok()?;
    let m: u32 = c.get(2)?.as_str().parse().ok()?;
    let d: u32 = c.get(3)?.as_str().parse().ok()?;
    NaiveDate::from_ymd_opt(y, m, d)
}

fn try_date_slash(text: &str) -> Option<NaiveDate> {
    let c = re_date_slash().captures(text)?;
    let p1: u32 = c.get(1)?.as_str().parse().ok()?;
    let p2: u32 = c.get(2)?.as_str().parse().ok()?;
    let p3_str = c.get(3)?.as_str();
    let year: i32 = expand_year(p3_str.parse().ok()?);
    // Assume MM/DD/YYYY (US format)
    NaiveDate::from_ymd_opt(year, p1, p2)
}

fn try_date_dash(text: &str) -> Option<NaiveDate> {
    let c = re_date_dash().captures(text)?;
    let p1: u32 = c.get(1)?.as_str().parse().ok()?;
    let p2: u32 = c.get(2)?.as_str().parse().ok()?;
    let p3_str = c.get(3)?.as_str();
    let year: i32 = expand_year(p3_str.parse().ok()?);
    NaiveDate::from_ymd_opt(year, p1, p2)
}

fn expand_year(y: i32) -> i32 {
    if y < 100 {
        2000 + y
    } else {
        y
    }
}

fn month_name_to_num(name: &str) -> Option<u32> {
    match name.to_lowercase().as_str() {
        "january" => Some(1),
        "february" => Some(2),
        "march" => Some(3),
        "april" => Some(4),
        "may" => Some(5),
        "june" => Some(6),
        "july" => Some(7),
        "august" => Some(8),
        "september" => Some(9),
        "october" => Some(10),
        "november" => Some(11),
        "december" => Some(12),
        _ => None,
    }
}

fn abbr_month_to_num(name: &str) -> Option<u32> {
    match name.to_lowercase().as_str() {
        "jan" => Some(1),
        "feb" => Some(2),
        "mar" => Some(3),
        "apr" => Some(4),
        "may" => Some(5),
        "jun" => Some(6),
        "jul" => Some(7),
        "aug" => Some(8),
        "sep" => Some(9),
        "oct" => Some(10),
        "nov" => Some(11),
        "dec" => Some(12),
        _ => None,
    }
}

// ── Amount parsing ────────────────────────────────────────────────────────────

fn parse_amount_str(s: &str) -> Option<i64> {
    let clean = s.replace(',', "");
    let dec = Decimal::from_str(&clean).ok()?;
    (dec * Decimal::from(100)).round().to_i64()
}

