        std::env::set_var("AEQUI_DAIMON_URL", "http://127.0.0.1:1");
        let handle = spawn_daimon_task(state, rx);

        // Signal shutdown after a brief delay
        tokio::time::sleep(Duration::from_millis(200)).await;
        let _ = tx.send(true);

