use axum::http::StatusCode;
use axum::response::{IntoResponse, Response};
use serde_json::json;

#[derive(Debug)]
pub enum ApiError {
    NotFound(String),
    BadRequest(String),
    Unauthorized,
    Internal(String),
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, msg),
            ApiError::BadRequest(msg) => (StatusCode::BAD_REQUEST, msg),
            ApiError::Unauthorized => (StatusCode::UNAUTHORIZED, "Unauthorized".to_string()),
            ApiError::Internal(msg) => {
                tracing::error!(error = %msg, "Internal server error");
                (StatusCode::INTERNAL_SERVER_ERROR, "Internal server error".to_string())
            }
        };

        let body = json!({ "error": message });
        (status, axum::Json(body)).into_response()
    }
}

impl From<sqlx::Error> for ApiError {
    fn from(e: sqlx::Error) -> Self {
        ApiError::Internal(e.to_string())
    }
}

impl From<aequi_core::LedgerError> for ApiError {
    fn from(e: aequi_core::LedgerError) -> Self {
        ApiError::BadRequest(e.to_string())
    }
}

use std::path::PathBuf;
use std::sync::Arc;

use anyhow::Result;
use tokio::sync::watch;
use tracing_subscriber::layer::SubscriberExt;
use tracing_subscriber::util::SubscriberInitExt;
use tracing_subscriber::EnvFilter;

mod daimon;
mod error;
pub(crate) mod oidc;
mod routes;
mod state;

use state::ServerState;

#[tokio::main]
async fn main() -> Result<()> {
    let filter =
        EnvFilter::try_from_default_env().unwrap_or_else(|_| "info".into());

    // AEQUI_LOG_FORMAT=json enables structured Bunyan-compatible JSON logging
    if std::env::var("AEQUI_LOG_FORMAT").as_deref() == Ok("json") {
        let formatting_layer =
            tracing_bunyan_formatter::BunyanFormattingLayer::new("aequi-server".into(), std::io::stdout);
        let json_fields_layer = tracing_bunyan_formatter::JsonStorageLayer;

        tracing_subscriber::registry()
            .with(filter)
            .with(json_fields_layer)
            .with(formatting_layer)
            .init();
    } else {
        tracing_subscriber::fmt()
            .with_env_filter(filter)
            .init();
    }

    let db_path = std::env::var("AEQUI_DB_PATH")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("aequi.db"));
    let port: u16 = std::env::var("AEQUI_PORT")
        .ok()
        .and_then(|p| p.parse().ok())
        .unwrap_or(8060);
    let api_key = std::env::var("AEQUI_API_KEY").ok();

    let db = aequi_storage::create_db(&db_path).await?;
    aequi_storage::seed_default_accounts(&db).await?;

    // Load email config from AEQUI_EMAIL_CONFIG env var (JSON string)
    let email_config: Option<aequi_email::EmailConfig> =
        std::env::var("AEQUI_EMAIL_CONFIG")
            .ok()
            .and_then(|json| serde_json::from_str(&json).ok());

    if email_config.is_some() {
        tracing::info!("Email delivery configured");
    }

    // Load OIDC config from AEQUI_OIDC_CONFIG env var (JSON string)
    let oidc: Option<oidc::JwksCache> = std::env::var("AEQUI_OIDC_CONFIG")
        .ok()
        .and_then(|json| serde_json::from_str::<oidc::OidcConfig>(&json).ok())
        .map(oidc::JwksCache::new);

    if oidc.is_some() {
        tracing::info!("OIDC authentication configured");
    }

    let stripe_webhook_secret = std::env::var("STRIPE_WEBHOOK_SECRET").ok();
    if stripe_webhook_secret.is_some() {
        tracing::info!("Stripe webhook listener configured");
    }

    // Load Plaid config from AEQUI_PLAID_CONFIG env var (JSON string)
    let plaid_config: Option<aequi_import::plaid::PlaidConfig> =
        std::env::var("AEQUI_PLAID_CONFIG")
            .ok()
            .and_then(|json| serde_json::from_str(&json).ok());

    if plaid_config.is_some() {
        tracing::info!("Plaid bank sync configured");
    }

    let state = Arc::new(ServerState {
        db,
        api_key,
        email_config,
        oidc,
        stripe_webhook_secret,
        plaid_config,
    });

    // Shutdown signal for background tasks
    let (shutdown_tx, shutdown_rx) = watch::channel(false);

    // Spawn daimon integration (non-blocking — server starts regardless)
    let daimon_handle = daimon::spawn_daimon_task(Arc::clone(&state), shutdown_rx);

    let app = routes::router(state);

    let listener = tokio::net::TcpListener::bind(format!("0.0.0.0:{port}")).await?;
    tracing::info!("aequi-server listening on port {port}");
    axum::serve(listener, app).await?;

    // Server stopped — shut down background tasks
    let _ = shutdown_tx.send(true);
    let _ = daimon_handle.await;

    Ok(())
}

use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use tokio::sync::RwLock;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OidcConfig {
    /// OIDC issuer URL (e.g. "https://accounts.google.com")
    pub issuer: String,
    /// Expected audience (client ID)
    pub audience: String,
}

/// Allowed JWT signing algorithms (pinned — prevents algorithm confusion attacks).
const ALLOWED_ALGORITHMS: &[Algorithm] = &[Algorithm::RS256, Algorithm::RS384, Algorithm::RS512];

/// Minimum interval between JWKS refreshes to prevent DoS via invalid tokens.
const MIN_REFRESH_INTERVAL_SECS: u64 = 300; // 5 minutes

/// Cached JWKS keys for token validation.
#[derive(Clone)]
pub struct JwksCache {
    config: OidcConfig,
    keys: Arc<RwLock<Option<jsonwebtoken::jwk::JwkSet>>>,
    last_refresh: Arc<RwLock<Option<std::time::Instant>>>,
}

#[derive(Debug, Deserialize)]
struct OidcDiscovery {
    jwks_uri: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Claims {
    pub sub: String,
    pub iss: String,
    pub aud: serde_json::Value,
    pub exp: u64,
    #[serde(default)]
    pub iat: Option<u64>,
    #[serde(default)]
    pub email: Option<String>,
}

impl JwksCache {
    pub fn new(config: OidcConfig) -> Self {
        Self {
            config,
            keys: Arc::new(RwLock::new(None)),
            last_refresh: Arc::new(RwLock::new(None)),
        }
    }

    /// Check if enough time has passed since the last JWKS refresh.
    async fn can_refresh(&self) -> bool {
        let last = self.last_refresh.read().await;
        match *last {
            None => true,
            Some(t) => t.elapsed().as_secs() >= MIN_REFRESH_INTERVAL_SECS,
        }
    }

    /// Fetch JWKS from the issuer's discovery endpoint.
    async fn refresh_keys(&self) -> Result<jsonwebtoken::jwk::JwkSet, String> {
        if !self.can_refresh().await {
            return Err("JWKS refresh rate limited".to_string());
        }

        let discovery_url = format!(
            "{}/.well-known/openid-configuration",
            self.config.issuer.trim_end_matches('/')
        );

        let client = reqwest::Client::builder()
            .timeout(std::time::Duration::from_secs(10))
            .build()
            .map_err(|e| format!("HTTP client error: {e}"))?;

        let discovery: OidcDiscovery = client
            .get(&discovery_url)
            .send()
            .await
            .map_err(|_| "OIDC discovery failed".to_string())?
            .json()
            .await
            .map_err(|_| "OIDC discovery parse failed".to_string())?;

        let jwks: jsonwebtoken::jwk::JwkSet = client
            .get(&discovery.jwks_uri)
            .send()
            .await
            .map_err(|_| "JWKS fetch failed".to_string())?
            .json()
            .await
            .map_err(|_| "JWKS parse failed".to_string())?;

        let mut cache = self.keys.write().await;
        *cache = Some(jwks.clone());

        let mut last = self.last_refresh.write().await;
        *last = Some(std::time::Instant::now());

        Ok(jwks)
    }

    /// Validate a JWT token. Returns claims on success.
    pub async fn validate_token(&self, token: &str) -> Result<Claims, String> {
        // Try cached keys first, refresh if needed
        let jwks = {
            let cache = self.keys.read().await;
            cache.clone()
        };

        let jwks = match jwks {
            Some(keys) => keys,
            None => self.refresh_keys().await?,
        };

        match self.try_validate(token, &jwks) {
            Ok(claims) => Ok(claims),
            Err(_) => {
                // Keys might be rotated — refresh and retry once (rate-limited)
                if self.can_refresh().await {
                    let refreshed = self.refresh_keys().await?;
                    self.try_validate(token, &refreshed)
                } else {
                    Err("JWT validation failed and JWKS refresh rate limited".to_string())
                }
            }
        }
    }

    fn try_validate(
        &self,
        token: &str,
        jwks: &jsonwebtoken::jwk::JwkSet,
    ) -> Result<Claims, String> {
        let header = jsonwebtoken::decode_header(token)
            .map_err(|e| format!("invalid JWT header: {e}"))?;

        // Reject algorithms not in the allowed list (prevents algorithm confusion)
        if !ALLOWED_ALGORITHMS.contains(&header.alg) {
            return Err(format!("algorithm {:?} not allowed", header.alg));
        }

        let kid = header
            .kid
            .as_ref()
            .ok_or("JWT missing kid header")?;

        let jwk = jwks
            .find(kid)
            .ok_or_else(|| format!("no matching key for kid: {kid}"))?;

        let decoding_key = DecodingKey::from_jwk(jwk)
            .map_err(|e| format!("invalid JWK: {e}"))?;

        let mut validation = Validation::new(header.alg);
        validation.set_audience(&[&self.config.audience]);
        validation.set_issuer(&[&self.config.issuer]);
        validation.leeway = 60; // 60 second clock skew tolerance

        let data = decode::<Claims>(token, &decoding_key, &validation)
            .map_err(|e| format!("JWT validation failed: {e}"))?;

        Ok(data.claims)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn oidc_config_serde() {
        let json = r#"{
            "issuer": "https://accounts.google.com",
            "audience": "my-client-id"
        }"#;
        let config: OidcConfig = serde_json::from_str(json).unwrap();
        assert_eq!(config.issuer, "https://accounts.google.com");
        assert_eq!(config.audience, "my-client-id");
    }

    #[test]
    fn jwks_cache_creation() {
        let config = OidcConfig {
            issuer: "https://example.com".into(),
            audience: "test".into(),
        };
        let _cache = JwksCache::new(config);
    }

    #[test]
    fn claims_deserialize() {
        let json = r#"{
            "sub": "user123",
            "iss": "https://example.com",
            "aud": "my-app",
            "exp": 9999999999,
            "email": "user@example.com"
        }"#;
        let claims: Claims = serde_json::from_str(json).unwrap();
        assert_eq!(claims.sub, "user123");
        assert_eq!(claims.email.unwrap(), "user@example.com");
    }

    #[test]
    fn invalid_token_rejected() {
        let config = OidcConfig {
            issuer: "https://example.com".into(),
            audience: "test".into(),
        };
        let cache = JwksCache::new(config);
        let jwks = jsonwebtoken::jwk::JwkSet { keys: vec![] };
        let result = cache.try_validate("not-a-jwt", &jwks);
        assert!(result.is_err());
    }

    #[test]
    fn hs256_algorithm_rejected() {
        let config = OidcConfig {
            issuer: "https://example.com".into(),
            audience: "test".into(),
        };
        let cache = JwksCache::new(config);
        let jwks = jsonwebtoken::jwk::JwkSet { keys: vec![] };
        // Craft a token header with HS256 (base64url encoded {"alg":"HS256","typ":"JWT"})
        let fake_token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxIn0.sig";
        let result = cache.try_validate(fake_token, &jwks);
        assert!(result.is_err());
        assert!(result.unwrap_err().contains("not allowed"));
    }
}

