fn plaid_client(state: &ServerState) -> Result<PlaidClient, ApiError> {
    let config = state
        .plaid_config
        .as_ref()
        .ok_or_else(|| ApiError::BadRequest("Plaid is not configured".to_string()))?;
    Ok(PlaidClient::new(config.clone()))
}

