// Router
// ---------------------------------------------------------------------------

pub fn routes() -> Router<Arc<ServerState>> {
    Router::new()
        .route("/plaid/link-token", post(create_link_token))
        .route("/plaid/exchange", post(exchange_public_token))
        .route("/plaid/sync", post(sync_transactions))
}

