use std::sync::Arc;

use axum::extract::State;
use axum::http::{HeaderMap, StatusCode};
use axum::response::IntoResponse;
use axum::routing::post;
use axum::Router;
use serde::{Deserialize, Serialize};

use aequi_core::{Money, TransactionLine, UnvalidatedTransaction, ValidatedTransaction};

use crate::state::ServerState;

// ── Stripe event types ─────────────────────────────────────────────────────

#[derive(Debug, Deserialize)]
struct StripeEvent {
    id: String,
    #[serde(rename = "type")]
    event_type: String,
    data: StripeEventData,
    created: i64,
}

#[derive(Debug, Deserialize)]
struct StripeEventData {
    object: serde_json::Value,
}

#[derive(Debug, Serialize)]
struct WebhookResponse {
    processed: bool,
    event_id: String,
    transaction_id: Option<i64>,
    message: String,
}

// ── Signature verification ─────────────────────────────────────────────────

fn verify_stripe_signature(payload: &[u8], sig_header: &str, secret: &str) -> bool {
    use sha2::{Digest, Sha256};

    // Parse Stripe-Signature header: t=timestamp,v1=signature
    let mut timestamp = None;
    let mut signatures = Vec::new();

    for part in sig_header.split(',') {
        let part = part.trim();
        if let Some(t) = part.strip_prefix("t=") {
            timestamp = Some(t.to_string());
        } else if let Some(v1) = part.strip_prefix("v1=") {
            signatures.push(v1.to_string());
        }
    }

    let timestamp = match timestamp {
        Some(t) => t,
        None => return false,
    };

    if signatures.is_empty() {
        return false;
    }

    // Compute expected signature: HMAC-SHA256(secret, "timestamp.payload")
    let signed_payload = format!("{timestamp}.{}", String::from_utf8_lossy(payload));

    // Use HMAC via manual SHA-256 (key XOR pad approach)
    let key = secret.as_bytes();
    let block_size = 64;

    let normalized_key = if key.len() > block_size {
        let mut hasher = Sha256::new();
        hasher.update(key);
        hasher.finalize().to_vec()
    } else {
        key.to_vec()
    };

    let mut ipad = vec![0x36u8; block_size];
    let mut opad = vec![0x5cu8; block_size];
    for (i, &b) in normalized_key.iter().enumerate() {
        ipad[i] ^= b;
        opad[i] ^= b;
    }

    let mut inner_hasher = Sha256::new();
    inner_hasher.update(&ipad);
    inner_hasher.update(signed_payload.as_bytes());
    let inner_hash = inner_hasher.finalize();

    let mut outer_hasher = Sha256::new();
    outer_hasher.update(&opad);
    outer_hasher.update(inner_hash);
    let expected = outer_hasher.finalize();

    let expected_hex = hex::encode(expected);

    // Constant-time comparison
    signatures.iter().any(|sig| {
        sig.len() == expected_hex.len()
            && sig
                .bytes()
                .zip(expected_hex.bytes())
                .fold(0u8, |acc, (a, b)| acc | (a ^ b))
                == 0
    })
}

/// Extract the `t=` timestamp from a Stripe-Signature header.
fn parse_stripe_timestamp(sig_header: &str) -> Option<i64> {
    sig_header
        .split(',')
        .find_map(|part| part.trim().strip_prefix("t="))
        .and_then(|t| t.parse::<i64>().ok())
}

// ── Account mapping ────────────────────────────────────────────────────────

/// Map Stripe event types to debit/credit account codes.
fn stripe_account_mapping(event_type: &str) -> Option<(&str, &str, &str)> {
    // Returns (description_prefix, debit_account, credit_account)
    match event_type {
        // Payout: money moves from Stripe to bank
        "payout.paid" => Some(("Stripe payout", "1000", "1030")),
        // Charge succeeded: revenue recognized
        "charge.succeeded" => Some(("Stripe charge", "1030", "4000")),
        // Refund: reverse the revenue
        "charge.refunded" => Some(("Stripe refund", "4000", "1030")),
        // Fee deducted (from balance transaction)
        "balance.available" => None, // handled via payout details
        _ => None,
    }
}

// ── Webhook handler ────────────────────────────────────────────────────────

async fn handle_webhook(
    State(state): State<Arc<ServerState>>,
    headers: HeaderMap,
    body: axum::body::Bytes,
) -> impl IntoResponse {
    // SECURITY: Always require webhook secret — reject if not configured
    let secret = match state.stripe_webhook_secret.as_ref() {
        Some(s) => s,
        None => {
            return (
                StatusCode::FORBIDDEN,
                axum::Json(serde_json::json!({ "error": "Stripe webhook not configured" })),
            );
        }
    };

    let sig = headers
        .get("stripe-signature")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");

    if !verify_stripe_signature(&body, sig, secret) {
        return (
            StatusCode::UNAUTHORIZED,
            axum::Json(serde_json::json!({ "error": "Invalid signature" })),
        );
    }

    // Replay protection: reject signatures older than 300 seconds
    if let Some(timestamp) = parse_stripe_timestamp(sig) {
        let now = chrono::Utc::now().timestamp();
        if (now - timestamp).unsigned_abs() > 300 {
            return (
                StatusCode::UNAUTHORIZED,
                axum::Json(serde_json::json!({ "error": "Signature timestamp too old" })),
            );
        }
    }

    let event: StripeEvent = match serde_json::from_slice(&body) {
        Ok(e) => e,
        Err(e) => {
            return (
                StatusCode::BAD_REQUEST,
                axum::Json(serde_json::json!({ "error": format!("Invalid event: {e}") })),
            );
        }
    };

    tracing::info!(
        event_id = %event.id,
        event_type = %event.event_type,
        "Processing Stripe webhook"
    );

    let mapping = match stripe_account_mapping(&event.event_type) {
        Some(m) => m,
        None => {
            return (
                StatusCode::OK,
                axum::Json(serde_json::json!(WebhookResponse {
                    processed: false,
                    event_id: event.id,
                    transaction_id: None,
                    message: format!("Event type '{}' not mapped", event.event_type),
                })),
            );
        }
    };

    let (desc_prefix, debit_code, credit_code) = mapping;
    let obj = &event.data.object;

    // Extract amount (Stripe uses cents)
    let amount_cents = obj
        .get("amount")
        .and_then(|v| v.as_i64())
        .unwrap_or(0);

    if amount_cents == 0 {
        return (
            StatusCode::OK,
            axum::Json(serde_json::json!(WebhookResponse {
                processed: false,
                event_id: event.id,
                transaction_id: None,
                message: "Zero amount, skipped".to_string(),
            })),
        );
    }

    // Extract date from event timestamp
    let date = chrono::DateTime::from_timestamp(event.created, 0)
        .map(|dt| dt.date_naive())
        .unwrap_or_else(|| chrono::Utc::now().date_naive());

    // Extract description details
    let stripe_id = obj
        .get("id")
        .and_then(|v| v.as_str())
        .unwrap_or(&event.id);
    let description = format!("{desc_prefix}: {stripe_id}");

    // Look up accounts
    let debit_account = match aequi_storage::get_account_by_code(&state.db, debit_code).await {
        Ok(Some(a)) => a,
        _ => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("Debit account {debit_code} not found") })),
            );
        }
    };

    let credit_account = match aequi_storage::get_account_by_code(&state.db, credit_code).await {
        Ok(Some(a)) => a,
        _ => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("Credit account {credit_code} not found") })),
            );
        }
    };

    // Handle Stripe fees as a separate line if present
    let fee_cents = obj
        .get("fee")
        .and_then(|v| v.as_i64())
        .unwrap_or(0);

    // Guard against negative amounts
    if amount_cents < 0 {
        return (
            StatusCode::BAD_REQUEST,
            axum::Json(serde_json::json!({ "error": "Negative amount" })),
        );
    }

    let debit_id = debit_account.id.unwrap_or(aequi_core::AccountId(0));
    let credit_id = credit_account.id.unwrap_or(aequi_core::AccountId(0));

    // Fee accounting: gross revenue + separate fee expense
    // Debit: full amount to debit account
    // Credit: full amount to credit account (revenue at gross)
    // If fees: Debit Bank Fees, Credit debit account (net payout reduced)
    let mut lines = vec![
        TransactionLine {
            account_id: debit_id,
            debit: Money::from_cents(amount_cents),
            credit: Money::from_cents(0),
            memo: Some(format!("Stripe {}", event.event_type)),
        },
        TransactionLine {
            account_id: credit_id,
            debit: Money::from_cents(0),
            credit: Money::from_cents(amount_cents),
            memo: None,
        },
    ];

    // Add fee as separate balanced entries (debit expense, credit asset)
    if fee_cents > 0 {
        match aequi_storage::get_account_by_code(&state.db, "5010").await {
            Ok(Some(fee_account)) => {
                let fee_id = fee_account.id.unwrap_or(aequi_core::AccountId(0));
                lines.push(TransactionLine {
                    account_id: fee_id,
                    debit: Money::from_cents(fee_cents),
                    credit: Money::from_cents(0),
                    memo: Some("Stripe processing fee".to_string()),
                });
                lines.push(TransactionLine {
                    account_id: debit_id,
                    debit: Money::from_cents(0),
                    credit: Money::from_cents(fee_cents),
                    memo: Some("Stripe fee offset".to_string()),
                });
            }
            _ => {
                tracing::warn!("Bank Fees account (5010) not found, fee not recorded separately");
            }
        }
    }

    let tx = UnvalidatedTransaction {
        date,
        description,
        lines,
        memo: Some(format!("Stripe event: {}", event.id)),
    };

    let validated = match ValidatedTransaction::validate(tx) {
        Ok(v) => v,
        Err(e) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("Transaction validation failed: {e}") })),
            );
        }
    };

    // Insert transaction atomically
    let mut db_tx = match state.db.begin().await {
        Ok(tx) => tx,
        Err(e) => {
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("DB transaction begin failed: {e}") })),
            );
        }
    };

    let row = match sqlx::query_as::<_, (i64,)>(
        "INSERT INTO transactions (date, description, memo, balanced_total_cents) VALUES (?, ?, ?, ?) RETURNING id"
    )
    .bind(validated.date.to_string())
    .bind(&validated.description)
    .bind(&validated.memo)
    .bind(validated.balanced_total.to_cents())
    .fetch_one(&mut *db_tx)
    .await
    {
        Ok(r) => r,
        Err(e) => {
            let _ = db_tx.rollback().await;
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("Failed to insert transaction: {e}") })),
            );
        }
    };

    let tx_id = row.0;

    for line in &validated.lines {
        if let Err(e) = sqlx::query(
            "INSERT INTO transaction_lines (transaction_id, account_id, debit_cents, credit_cents, memo) VALUES (?, ?, ?, ?, ?)"
        )
        .bind(tx_id)
        .bind(line.account_id.0)
        .bind(line.debit.to_cents())
        .bind(line.credit.to_cents())
        .bind(&line.memo)
        .execute(&mut *db_tx)
        .await
        {
            let _ = db_tx.rollback().await;
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                axum::Json(serde_json::json!({ "error": format!("Failed to insert line: {e}") })),
            );
        }
    }

    if let Err(e) = db_tx.commit().await {
        return (
            StatusCode::INTERNAL_SERVER_ERROR,
            axum::Json(serde_json::json!({ "error": format!("DB commit failed: {e}") })),
        );
    }

    tracing::info!(
        event_id = %event.id,
        transaction_id = tx_id,
        amount_cents,
        "Stripe webhook processed"
    );

    (
        StatusCode::OK,
        axum::Json(serde_json::json!(WebhookResponse {
            processed: true,
            event_id: event.id,
            transaction_id: Some(tx_id),
            message: "Transaction created".to_string(),
        })),
    )
}

pub fn routes() -> Router<Arc<ServerState>> {
    Router::new().route("/stripe/webhook", post(handle_webhook))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn payout_maps_to_checking() {
        let mapping = stripe_account_mapping("payout.paid");
        assert!(mapping.is_some());
        let (desc, debit, credit) = mapping.unwrap();
        assert_eq!(desc, "Stripe payout");
        assert_eq!(debit, "1000"); // Checking
        assert_eq!(credit, "1030"); // Undeposited Funds
    }

    #[test]
    fn charge_maps_to_revenue() {
        let mapping = stripe_account_mapping("charge.succeeded");
        assert!(mapping.is_some());
        let (_, debit, credit) = mapping.unwrap();
        assert_eq!(debit, "1030"); // Undeposited Funds
        assert_eq!(credit, "4000"); // Services Revenue
    }

    #[test]
    fn refund_reverses_revenue() {
        let mapping = stripe_account_mapping("charge.refunded");
        assert!(mapping.is_some());
        let (_, debit, credit) = mapping.unwrap();
        assert_eq!(debit, "4000"); // Revenue reversal
        assert_eq!(credit, "1030"); // Undeposited Funds
    }

    #[test]
    fn unknown_event_returns_none() {
        assert!(stripe_account_mapping("customer.created").is_none());
        assert!(stripe_account_mapping("invoice.payment_failed").is_none());
    }

    #[test]
    fn signature_verification_rejects_bad_sig() {
        let payload = b"test payload";
        let bad_sig = "t=1234567890,v1=badhex";
        assert!(!verify_stripe_signature(payload, bad_sig, "whsec_test"));
    }

    #[test]
    fn signature_verification_rejects_missing_timestamp() {
        assert!(!verify_stripe_signature(b"test", "v1=abc", "secret"));
    }

    #[test]
    fn signature_verification_rejects_missing_signature() {
        assert!(!verify_stripe_signature(b"test", "t=123", "secret"));
    }

    #[test]
    fn valid_signature_accepted() {
        use sha2::{Digest, Sha256};

        let secret = "whsec_test_secret";
        let timestamp = "1678886400";
        let payload = r#"{"id":"evt_123","type":"charge.succeeded"}"#;

        let signed = format!("{timestamp}.{payload}");

        // Compute HMAC-SHA256 manually
        let key = secret.as_bytes();
        let block_size = 64;
        let mut ipad = vec![0x36u8; block_size];
        let mut opad = vec![0x5cu8; block_size];
        for (i, &b) in key.iter().enumerate() {
            ipad[i] ^= b;
            opad[i] ^= b;
        }
        let mut inner = Sha256::new();
        inner.update(&ipad);
        inner.update(signed.as_bytes());
        let inner_hash = inner.finalize();
        let mut outer = Sha256::new();
        outer.update(&opad);
        outer.update(inner_hash);
        let expected = hex::encode(outer.finalize());

        let sig_header = format!("t={timestamp},v1={expected}");
        assert!(verify_stripe_signature(payload.as_bytes(), &sig_header, secret));
    }

    #[test]
    fn stripe_event_deserializes() {
        let json = r#"{
            "id": "evt_test_123",
            "type": "charge.succeeded",
            "created": 1678886400,
            "data": {
                "object": {
                    "id": "ch_abc",
                    "amount": 5000,
                    "fee": 175,
                    "currency": "usd"
                }
            }
        }"#;
        let event: StripeEvent = serde_json::from_str(json).unwrap();
        assert_eq!(event.event_type, "charge.succeeded");
        assert_eq!(event.data.object["amount"], 5000);
        assert_eq!(event.data.object["fee"], 175);
    }
}

use std::sync::Arc;

use axum::extract::{Query, State};
use axum::routing::{get, post};
use axum::{Json, Router};
use serde::{Deserialize, Serialize};

use chrono::Datelike;

use aequi_core::{FiscalYear, Money, Quarter};

use crate::error::ApiError;
use crate::state::ServerState;

#[derive(Deserialize)]
struct TaxQuery {
    year: Option<u16>,
    quarter: Option<u8>,
}

#[derive(Serialize)]
struct EstimateOut {
    year: u16,
    quarter: String,
    ytd_gross_income_cents: i64,
    ytd_net_profit_cents: i64,
    se_tax_cents: i64,
    income_tax_cents: i64,
    total_tax_cents: i64,
    quarterly_payment_cents: i64,
    payment_due_date: String,
}

fn load_rules(year: u16) -> Result<aequi_core::TaxRules, ApiError> {
    let toml_str = include_str!("../../../../rules/tax/us/2026.toml");
    let rules =
        aequi_core::TaxRules::from_toml(toml_str).map_err(|e| ApiError::Internal(e.to_string()))?;
    if rules.year.value != year {
        return Err(ApiError::BadRequest(format!(
            "Tax rules for year {year} not available"
        )));
    }
    Ok(rules)
}

async fn quarterly_estimate(
    State(state): State<Arc<ServerState>>,
    Query(q): Query<TaxQuery>,
) -> Result<Json<EstimateOut>, ApiError> {
    let now = chrono::Utc::now().date_naive();
    let yr = q.year.unwrap_or(now.year_ce().1 as u16);
    let qtr = q.quarter.and_then(Quarter::new).unwrap_or(Quarter::Q1);

    let rules = load_rules(yr)?;
    let fy = FiscalYear::new(yr);

    let prior = aequi_storage::get_prior_year_total_tax(&state.db, yr)
        .await?
        .map(Money::from_cents);

    let snapshot = aequi_storage::build_ledger_snapshot(&state.db, fy, prior).await?;
    let est = aequi_core::compute_quarterly_estimate(&rules, &snapshot, qtr);

    Ok(Json(EstimateOut {
        year: est.year,
        quarter: est.quarter.to_string(),
        ytd_gross_income_cents: est.ytd_gross_income.to_cents(),
        ytd_net_profit_cents: est.ytd_net_profit.to_cents(),
        se_tax_cents: est.se_tax_amount.to_cents(),
        income_tax_cents: est.estimated_income_tax.to_cents(),
        total_tax_cents: est.total_tax_estimate.to_cents(),
        quarterly_payment_cents: est.quarterly_payment.to_cents(),
        payment_due_date: est.payment_due_date.to_string(),
    }))
}

#[derive(Deserialize)]
struct PaymentInput {
    year: u16,
    quarter: u8,
    amount_cents: i64,
    date: String,
}

async fn record_payment(
    State(state): State<Arc<ServerState>>,
    Json(input): Json<PaymentInput>,
) -> Result<Json<()>, ApiError> {
    aequi_storage::record_tax_payment(
        &state.db,
        input.year,
        input.quarter,
        input.amount_cents,
        &input.date,
    )
    .await?;
    Ok(Json(()))
}

async fn schedule_c(
    State(state): State<Arc<ServerState>>,
    Query(q): Query<TaxQuery>,
) -> Result<Json<aequi_core::ScheduleCPreview>, ApiError> {
    let yr = q.year.unwrap_or(2026);
    let rules = load_rules(yr)?;
    let fy = FiscalYear::new(yr);
    let snapshot = aequi_storage::build_ledger_snapshot(&state.db, fy, None).await?;
    let preview = aequi_core::tax::engine::schedule_c_preview(&rules, &snapshot);
    Ok(Json(preview))
}

pub fn routes() -> Router<Arc<ServerState>> {
    Router::new()
        .route("/tax/quarterly-estimate", get(quarterly_estimate))
        .route("/tax/schedule-c", get(schedule_c))
        .route("/tax/payments", post(record_payment))
}

use std::sync::Arc;

use axum::extract::State;
use axum::routing::get;
use axum::{Json, Router};
use serde::{Deserialize, Serialize};

use aequi_core::{Money, TransactionLine, UnvalidatedTransaction, ValidatedTransaction};

use crate::error::ApiError;
use crate::state::ServerState;

#[derive(Deserialize)]
struct CreateTransaction {
    date: String,
    description: String,
    lines: Vec<LineInput>,
    memo: Option<String>,
}

#[derive(Deserialize)]
struct LineInput {
    account_code: String,
    debit_cents: i64,
    credit_cents: i64,
    memo: Option<String>,
}

#[derive(Serialize)]
struct TransactionOut {
    id: i64,
    date: String,
    description: String,
    balanced_total_cents: i64,
    memo: Option<String>,
}

async fn list_transactions(
    State(state): State<Arc<ServerState>>,
) -> Result<Json<Vec<TransactionOut>>, ApiError> {
    let rows = sqlx::query_as::<_, (i64, String, String, Option<String>, i64)>(
        "SELECT id, date, description, memo, balanced_total_cents FROM transactions ORDER BY date DESC, id DESC LIMIT 1000"
    )
    .fetch_all(&state.db)
    .await?;

    Ok(Json(
        rows.into_iter()
            .map(|r| TransactionOut {
                id: r.0,
                date: r.1,
                description: r.2,
                memo: r.3,
                balanced_total_cents: r.4,
            })
            .collect(),
    ))
}

async fn create_transaction(
    State(state): State<Arc<ServerState>>,
    Json(input): Json<CreateTransaction>,
) -> Result<Json<TransactionOut>, ApiError> {
    if input.description.trim().is_empty() {
        return Err(ApiError::BadRequest("Description is required".to_string()));
    }
    if input.lines.is_empty() {
        return Err(ApiError::BadRequest("At least one line is required".to_string()));
    }
    for line in &input.lines {
        if line.debit_cents < 0 || line.credit_cents < 0 {
            return Err(ApiError::BadRequest("Debit and credit must be non-negative".to_string()));
        }
    }

    let date = chrono::NaiveDate::parse_from_str(&input.date, "%Y-%m-%d")
        .map_err(|e| ApiError::BadRequest(format!("Invalid date: {e}")))?;

    let mut lines = Vec::new();
    for line in input.lines {
        let account = aequi_storage::get_account_by_code(&state.db, &line.account_code)
            .await?
            .ok_or_else(|| {
                ApiError::NotFound(format!("Account {} not found", line.account_code))
            })?;

        lines.push(TransactionLine {
            account_id: account.id.ok_or_else(|| ApiError::Internal("Account missing ID".to_string()))?,
            debit: Money::from_cents(line.debit_cents),
            credit: Money::from_cents(line.credit_cents),
            memo: line.memo,
        });
    }

    let tx = UnvalidatedTransaction {
        date,
        description: input.description,
        lines,
        memo: input.memo,
    };

    let validated = ValidatedTransaction::validate(tx)?;

    let mut db_tx = state.db.begin().await?;

    let row = sqlx::query_as::<_, (i64,)>(
        "INSERT INTO transactions (date, description, memo, balanced_total_cents) VALUES (?, ?, ?, ?) RETURNING id"
    )
    .bind(validated.date.to_string())
    .bind(&validated.description)
    .bind(&validated.memo)
    .bind(validated.balanced_total.to_cents())
    .fetch_one(&mut *db_tx)
    .await?;

    let id = row.0;

    for line in &validated.lines {
        sqlx::query(
            "INSERT INTO transaction_lines (transaction_id, account_id, debit_cents, credit_cents, memo) VALUES (?, ?, ?, ?, ?)"
        )
        .bind(id)
        .bind(line.account_id.0)
        .bind(line.debit.to_cents())
        .bind(line.credit.to_cents())
        .bind(&line.memo)
        .execute(&mut *db_tx)
        .await?;
    }

    db_tx.commit().await?;

    Ok(Json(TransactionOut {
        id,
        date: validated.date.to_string(),
        description: validated.description,
        balanced_total_cents: validated.balanced_total.to_cents(),
        memo: validated.memo,
    }))
}

pub fn routes() -> Router<Arc<ServerState>> {
    Router::new().route(
        "/transactions",
        get(list_transactions).post(create_transaction),
    )
}

//! Backup and restore for Aequi data.
//!
//! Creates a compressed tarball containing the SQLite database snapshot
//! and the attachments directory. Restore extracts to a target location.

use flate2::read::GzDecoder;
use flate2::write::GzEncoder;
use flate2::Compression;
use std::fs;
use std::io;
use std::path::{Path, PathBuf};

/// Metadata written into the backup archive as `manifest.json`.
#[derive(serde::Serialize, serde::Deserialize, Debug)]
pub struct BackupManifest {
    pub version: String,
    pub created_at: String,
    pub schema_version: i64,
    pub db_size_bytes: u64,
    pub attachment_count: u64,
}

/// Create a compressed backup archive at `output_path`.
///
/// The archive contains:
/// - `manifest.json` — backup metadata
/// - `ledger.db` — SQLite database snapshot (via VACUUM INTO)
/// - `attachments/` — all receipt attachments (if directory exists and is non-empty)
///
/// Uses SQLite's `VACUUM INTO` for a consistent point-in-time snapshot,
/// avoiding issues with WAL files and concurrent access.
pub async fn create_backup(
    pool: &crate::db::DbPool,
    _db_path: &Path,
    attachments_dir: &Path,
    output_path: &Path,
    app_version: &str,
) -> Result<BackupManifest, BackupError> {
    // Create a clean snapshot of the database
    let temp_dir = output_path.parent().unwrap_or(Path::new("."));
    let snapshot_path = temp_dir.join(".aequi-backup-snapshot.db");

    // Clean up any previous failed snapshot
    let _ = fs::remove_file(&snapshot_path);

    // VACUUM INTO creates an atomic, consistent copy.
    // Canonicalize and validate the path to prevent injection via crafted filenames.
    let canonical = snapshot_path
        .canonicalize()
        .or_else(|_| {
            // File doesn't exist yet; canonicalize parent and append filename
            let parent = snapshot_path
                .parent()
                .unwrap_or(Path::new("."))
                .canonicalize()
                .map_err(|e| BackupError::Io(e.to_string()))?;
            Ok::<PathBuf, BackupError>(parent.join(snapshot_path.file_name().unwrap_or_default()))
        })?;
    let path_str = canonical.to_string_lossy();
    // Reject paths containing single quotes to prevent SQL injection
    if path_str.contains('\'') {
        return Err(BackupError::Io("Backup path must not contain single quotes".into()));
    }
    sqlx::query(&format!("VACUUM INTO '{path_str}'"))
        .execute(pool)
        .await
        .map_err(|e| BackupError::Database(e.to_string()))?;

    let db_size = fs::metadata(&snapshot_path).map(|m| m.len()).unwrap_or(0);

    // Count attachments
    let attachment_count = count_files(attachments_dir);

    // Get schema version
    let schema_version = crate::migrate::current_version(pool).await.unwrap_or(0);

    let manifest = BackupManifest {
        version: app_version.to_string(),
        created_at: chrono::Utc::now().to_rfc3339(),
        schema_version,
        db_size_bytes: db_size,
        attachment_count,
    };

    // Build the tar.gz archive
    let output_file = fs::File::create(output_path)
        .map_err(|e| BackupError::Io(format!("Failed to create backup file: {e}")))?;
    let encoder = GzEncoder::new(output_file, Compression::default());
    let mut archive = tar::Builder::new(encoder);

    // Add manifest
    let manifest_json = serde_json::to_string_pretty(&manifest)
        .map_err(|e| BackupError::Io(format!("Failed to serialize manifest: {e}")))?;
    let manifest_bytes = manifest_json.as_bytes();
    let mut header = tar::Header::new_gnu();
    header.set_size(manifest_bytes.len() as u64);
    header.set_mode(0o644);
    header.set_cksum();
    archive
        .append_data(&mut header, "manifest.json", manifest_bytes)
        .map_err(|e| BackupError::Io(format!("Failed to add manifest: {e}")))?;

    // Add database snapshot
    archive
        .append_path_with_name(&snapshot_path, "ledger.db")
        .map_err(|e| BackupError::Io(format!("Failed to add database: {e}")))?;

    // Add attachments directory
    if attachments_dir.is_dir() && attachment_count > 0 {
        archive
            .append_dir_all("attachments", attachments_dir)
            .map_err(|e| BackupError::Io(format!("Failed to add attachments: {e}")))?;
    }

    archive
        .finish()
        .map_err(|e| BackupError::Io(format!("Failed to finalize archive: {e}")))?;

    // Clean up snapshot
    let _ = fs::remove_file(&snapshot_path);

    Ok(manifest)
}

/// Restore from a backup archive.
///
/// Extracts the database and attachments to `target_dir`.
/// Returns the path to the restored database file.
///
/// **Warning**: This overwrites existing data in `target_dir`.
pub fn restore_backup(
    archive_path: &Path,
    target_dir: &Path,
) -> Result<RestoreResult, BackupError> {
    let file = fs::File::open(archive_path)
        .map_err(|e| BackupError::Io(format!("Failed to open backup: {e}")))?;
    let decoder = GzDecoder::new(file);
    let mut archive = tar::Archive::new(decoder);

    fs::create_dir_all(target_dir)
        .map_err(|e| BackupError::Io(format!("Failed to create target directory: {e}")))?;

    let mut manifest: Option<BackupManifest> = None;

    for entry in archive
        .entries()
        .map_err(|e| BackupError::Io(format!("Failed to read archive: {e}")))?
    {
        let mut entry = entry.map_err(|e| BackupError::Io(format!("Failed to read entry: {e}")))?;

        let path = entry
            .path()
            .map_err(|e| BackupError::Io(format!("Invalid path in archive: {e}")))?
            .to_path_buf();

        // Security: reject absolute paths, path traversal, and symlinks
        if path.is_absolute()
            || path
                .components()
                .any(|c| c == std::path::Component::ParentDir)
        {
            return Err(BackupError::InvalidArchive(
                "Archive contains path traversal".to_string(),
            ));
        }
        if entry.header().entry_type().is_symlink()
            || entry.header().entry_type().is_hard_link()
        {
            return Err(BackupError::InvalidArchive(
                "Archive contains symlinks (not allowed)".to_string(),
            ));
        }

        if path == Path::new("manifest.json") {
            let mut buf = String::new();
            io::Read::read_to_string(&mut entry, &mut buf)
                .map_err(|e| BackupError::Io(format!("Failed to read manifest: {e}")))?;
            manifest = Some(
                serde_json::from_str(&buf)
                    .map_err(|e| BackupError::InvalidArchive(format!("Invalid manifest: {e}")))?,
            );
        } else {
            let target = target_dir.join(&path);
            if let Some(parent) = target.parent() {
                fs::create_dir_all(parent)
                    .map_err(|e| BackupError::Io(format!("Failed to create dir: {e}")))?;
            }
            entry.unpack(&target).map_err(|e| {
                BackupError::Io(format!("Failed to extract {}: {e}", path.display()))
            })?;
        }
    }

    let manifest = manifest
        .ok_or_else(|| BackupError::InvalidArchive("Archive missing manifest.json".to_string()))?;

    Ok(RestoreResult {
        db_path: target_dir.join("ledger.db"),
        attachments_dir: target_dir.join("attachments"),
        manifest,
    })
}

/// Result of a successful restore operation.
pub struct RestoreResult {
    pub db_path: PathBuf,
    pub attachments_dir: PathBuf,
    pub manifest: BackupManifest,
}

/// Count files recursively in a directory.
fn count_files(dir: &Path) -> u64 {
    if !dir.is_dir() {
        return 0;
    }
    walkdir(dir)
}

fn walkdir(dir: &Path) -> u64 {
    let mut count = 0;
    if let Ok(entries) = fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_file() {
                count += 1;
            } else if path.is_dir() {
                count += walkdir(&path);
            }
        }
    }
    count
}

#[derive(Debug, thiserror::Error)]
pub enum BackupError {
    #[error("Database error: {0}")]
    Database(String),
    #[error("IO error: {0}")]
    Io(String),
    #[error("Invalid archive: {0}")]
    InvalidArchive(String),
}

#[cfg(test)]
mod tests {
    use super::*;
    use sqlx::sqlite::SqlitePoolOptions;

    async fn test_pool_at(path: &Path) -> crate::db::DbPool {
        let pool = SqlitePoolOptions::new()
            .max_connections(1)
            .connect(&format!("sqlite:{}?mode=rwc", path.display()))
            .await
            .unwrap();
        sqlx::query("PRAGMA journal_mode = WAL")
            .execute(&pool)
            .await
            .unwrap();
        crate::migrate::run_migrations(&pool).await.unwrap();
        pool
    }

    #[tokio::test]
    async fn backup_creates_archive() {
        let tmp = tempfile::tempdir().unwrap();
        let db_path = tmp.path().join("ledger.db");
        let attachments = tmp.path().join("attachments");
        fs::create_dir_all(&attachments).unwrap();
        let output = tmp.path().join("backup.tar.gz");

        let pool = test_pool_at(&db_path).await;

        // Insert test data
        sqlx::query("INSERT OR IGNORE INTO accounts (code, name, account_type) VALUES ('1000', 'Cash', 'Asset')")
            .execute(&pool)
            .await
            .unwrap();

        let manifest = create_backup(&pool, &db_path, &attachments, &output, "2026.3.10")
            .await
            .unwrap();

        assert!(output.exists());
        assert_eq!(manifest.version, "2026.3.10");
        assert!(manifest.schema_version >= 1);
        assert!(manifest.db_size_bytes > 0);
    }

    #[tokio::test]
    async fn backup_and_restore_roundtrip() {
        let tmp = tempfile::tempdir().unwrap();
        let db_path = tmp.path().join("ledger.db");
        let attachments = tmp.path().join("attachments");
        fs::create_dir_all(&attachments).unwrap();

        // Create a test attachment
        fs::write(attachments.join("test.jpg"), b"fake image data").unwrap();

        let pool = test_pool_at(&db_path).await;
        sqlx::query("INSERT OR IGNORE INTO accounts (code, name, account_type) VALUES ('2000', 'Revenue', 'Income')")
            .execute(&pool)
            .await
            .unwrap();

        let output = tmp.path().join("backup.tar.gz");
        create_backup(&pool, &db_path, &attachments, &output, "2026.3.10")
            .await
            .unwrap();

        // Restore to a new location
        let restore_dir = tmp.path().join("restored");
        let result = restore_backup(&output, &restore_dir).unwrap();

        assert!(result.db_path.exists());
        assert_eq!(result.manifest.version, "2026.3.10");
        assert_eq!(result.manifest.attachment_count, 1);

        // Verify the restored database has the data
        let restored_pool = SqlitePoolOptions::new()
            .max_connections(1)
            .connect(&format!("sqlite:{}?mode=rwc", result.db_path.display()))
            .await
            .unwrap();
        let row: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM accounts WHERE code = '2000'")
            .fetch_one(&restored_pool)
            .await
            .unwrap();
        assert_eq!(row.0, 1);

        // Verify attachment was restored
        assert!(result.attachments_dir.join("test.jpg").exists());
    }

    #[tokio::test]
    async fn backup_empty_attachments() {
        let tmp = tempfile::tempdir().unwrap();
        let db_path = tmp.path().join("ledger.db");
        let attachments = tmp.path().join("attachments");
        fs::create_dir_all(&attachments).unwrap();
        let output = tmp.path().join("backup.tar.gz");

        let pool = test_pool_at(&db_path).await;
        let manifest = create_backup(&pool, &db_path, &attachments, &output, "2026.3.10")
            .await
            .unwrap();

        assert_eq!(manifest.attachment_count, 0);
        assert!(output.exists());
    }

    #[test]
    fn restore_rejects_invalid_archive() {
        let tmp = tempfile::tempdir().unwrap();
        let bad_file = tmp.path().join("bad.tar.gz");
        fs::write(&bad_file, b"not a valid archive").unwrap();

        let result = restore_backup(&bad_file, &tmp.path().join("out"));
        assert!(result.is_err());
    }

    #[test]
    fn count_files_empty_dir() {
        let tmp = tempfile::tempdir().unwrap();
        assert_eq!(count_files(tmp.path()), 0);
    }

    #[test]
    fn count_files_with_nested() {
        let tmp = tempfile::tempdir().unwrap();
        fs::create_dir_all(tmp.path().join("sub")).unwrap();
        fs::write(tmp.path().join("a.txt"), b"a").unwrap();
        fs::write(tmp.path().join("sub/b.txt"), b"b").unwrap();
        assert_eq!(count_files(tmp.path()), 2);
    }

    #[test]
    fn count_files_nonexistent() {
        assert_eq!(count_files(Path::new("/nonexistent/path")), 0);
    }
}

use aequi_core::{
    Account, AccountId, AccountType, FiscalYear, LedgerSnapshot, Money, ScheduleCLine,
    DEFAULT_ACCOUNTS,
};
use sqlx::{sqlite::SqlitePoolOptions, Pool, Sqlite};
use std::collections::BTreeMap;
use std::path::Path;

pub type DbPool = Pool<Sqlite>;

pub async fn create_db(path: &Path) -> Result<DbPool, sqlx::Error> {
    // WAL mode supports concurrent readers + one writer.
    // 4 connections allows parallel reads without serializing everything.
    let pool = SqlitePoolOptions::new()
        .max_connections(4)
        .connect(&format!("sqlite:{}?mode=rwc", path.display()))
        .await?;

    sqlx::query("PRAGMA journal_mode = WAL")
        .execute(&pool)
        .await?;
    sqlx::query("PRAGMA foreign_keys = ON")
        .execute(&pool)
        .await?;
    sqlx::query("PRAGMA synchronous = NORMAL")
        .execute(&pool)
        .await?;
    sqlx::query("PRAGMA busy_timeout = 5000")
        .execute(&pool)
        .await?;
    sqlx::query("PRAGMA cache_size = -32000")
        .execute(&pool)
        .await?;

    crate::migrate::run_migrations(&pool).await?;

    Ok(pool)
}

pub async fn seed_default_accounts(pool: &DbPool) -> Result<(), sqlx::Error> {
    for (code, name, account_type, schedule_c_line) in DEFAULT_ACCOUNTS {
        let type_str = match account_type {
            AccountType::Asset => "Asset",
            AccountType::Liability => "Liability",
            AccountType::Equity => "Equity",
            AccountType::Income => "Income",
            AccountType::Expense => "Expense",
        };

        sqlx::query(
            "INSERT OR IGNORE INTO accounts (code, name, account_type, is_archetype, schedule_c_line) VALUES (?, ?, ?, 1, ?)"
        )
        .bind(code)
        .bind(name)
        .bind(type_str)
        .bind(if schedule_c_line.is_empty() { None } else { Some(*schedule_c_line) })
        .execute(pool)
        .await?;
    }

    Ok(())
}

type AccountRow = (i64, String, String, String, i64, i64, Option<String>);

fn row_to_account(r: AccountRow) -> Account {
    let account_type = match r.3.as_str() {
        "Asset" => AccountType::Asset,
        "Liability" => AccountType::Liability,
        "Equity" => AccountType::Equity,
        "Income" => AccountType::Income,
        "Expense" => AccountType::Expense,
        _ => AccountType::Asset,
    };
    Account {
        id: Some(AccountId(r.0)),
        code: r.1,
        name: r.2,
        account_type,
        is_archetype: r.4 != 0,
        is_archived: r.5 != 0,
        schedule_c_line: r.6,
    }
}

pub async fn get_all_accounts(pool: &DbPool) -> Result<Vec<Account>, sqlx::Error> {
    let rows = sqlx::query_as::<_, AccountRow>(
        "SELECT id, code, name, account_type, is_archetype, is_archived, schedule_c_line FROM accounts WHERE is_archived = 0 ORDER BY code"
    )
    .fetch_all(pool)
    .await?;

    Ok(rows.into_iter().map(row_to_account).collect())
}

pub async fn get_account_by_code(
    pool: &DbPool,
    code: &str,
) -> Result<Option<Account>, sqlx::Error> {
    let row = sqlx::query_as::<_, AccountRow>(
        "SELECT id, code, name, account_type, is_archetype, is_archived, schedule_c_line FROM accounts WHERE code = ?"
    )
    .bind(code)
    .fetch_optional(pool)
    .await?;

    Ok(row.map(row_to_account))
}

